from typing import List
from collections import deque

class Solution:
    def shortestDistanceAfterQueries(self, n: int, queries: List[List[int]]) -> List[int]:
        # Graph starts with edges i -> i+1
        graph = [[] for _ in range(n)]
        for i in range(n - 1):
            graph[i].append(i + 1)

        ans = []

        for u, v in queries:
            graph[u].append(v)

            # BFS to find shortest path from 0 to n-1
            dist = [-1] * n
            dist[0] = 0
            q = deque([0])

            while q:
                node = q.popleft()
                if node == n - 1:
                    break
                for nei in graph[node]:
                    if dist[nei] == -1:
                        dist[nei] = dist[node] + 1
                        q.append(nei)

            ans.append(dist[n - 1])

        return ans

class Solution:
    def subsequenceCount(self, nums: List[int]) -> int:
        MOD = 10**9 + 7

        even_count = 1  # empty subsequence
        odd_count = 0

        for num in nums:
            if num % 2 == 0:
                even_count = (even_count * 2) % MOD
                odd_count = (odd_count * 2) % MOD
            else:
                new_even = (even_count + odd_count) % MOD
                new_odd = (odd_count + even_count) % MOD
                even_count, odd_count = new_even, new_odd

        return odd_count

class Solution:
    def finalPositionOfSnake(self, n: int, commands: List[str]) -> int:
        row, col = 0, 0

        for cmd in commands:
            if cmd == "UP":
                row -= 1
            elif cmd == "DOWN":
                row += 1
            elif cmd == "LEFT":
                col -= 1
            else:  # "RIGHT"
                col += 1

        return row * n + col

class Solution:
    def countGoodNodes(self, edges: List[List[int]]) -> int:
        n = len(edges) + 1
        graph = [[] for _ in range(n)]
        for u, v in edges:
            graph[u].append(v)
            graph[v].append(u)

        good = 0

        def dfs(node: int, parent: int) -> int:
            nonlocal good
            child_sizes = []

            size = 1
            for nei in graph[node]:
                if nei == parent:
                    continue
                sub_size = dfs(nei, node)
                child_sizes.append(sub_size)
                size += sub_size

            if len(child_sizes) <= 1:
                good += 1
            else:
                first = child_sizes[0]
                if all(x == first for x in child_sizes):
                    good += 1

            return size

        dfs(0, -1)
        return good

from typing import List
from math import inf

class Solution:
    def minimumCost(self, target: str, words: List[str], costs: List[int]) -> int:
        n = len(target)

        # Keep only the minimum cost for each distinct word
        best_cost = {}
        for w, c in zip(words, costs):
            if w not in best_cost or c < best_cost[w]:
                best_cost[w] = c

        # Group words by their starting character to reduce checks
        groups = [[] for _ in range(26)]
        for w, c in best_cost.items():
            groups[ord(w[0]) - 97].append((w, c))

        # dp[i] = minimum cost to build target[:i]
        dp = [inf] * (n + 1)
        dp[0] = 0

        for i in range(n):
            if dp[i] == inf:
                continue
            bucket = groups[ord(target[i]) - 97]
            for w, c in bucket:
                m = len(w)
                if i + m <= n and target[i:i + m] == w:
                    dp[i + m] = min(dp[i + m], dp[i] + c)

        return -1 if dp[n] == inf else dp[n]

class Solution:
    def resultsArray(self, nums: List[int], k: int) -> List[int]:
        n = len(nums)

        if k == 1:
            return nums[:]

        # good[i] = whether nums[i] and nums[i+1] differ by exactly 1 in ascending order
        good = [0] * (n - 1)
        for i in range(n - 1):
            if nums[i + 1] == nums[i] + 1:
                good[i] = 1

        # Prefix sum of bad transitions
        bad_prefix = [0] * n
        for i in range(n - 1):
            bad_prefix[i + 1] = bad_prefix[i] + (1 - good[i])

        res = []
        for i in range(n - k + 1):
            # Window nums[i..i+k-1] is valid if all k-1 adjacent pairs are good
            bad_count = bad_prefix[i + k - 1] - bad_prefix[i]
            if bad_count == 0:
                res.append(nums[i + k - 1])
            else:
                res.append(-1)

        return res

from typing import List

class Solution:
    def resultsArray(self, nums: List[int], k: int) -> List[int]:
        n = len(nums)

        if k == 1:
            return nums[:]

        # good[i] = 1 if nums[i] and nums[i+1] differ by exactly 1
        good = [0] * (n - 1)
        for i in range(n - 1):
            if nums[i + 1] == nums[i] + 1:
                good[i] = 1

        # Prefix sum over good to count valid adjacent pairs in any window
        prefix = [0] * n
        for i in range(n - 1):
            prefix[i + 1] = prefix[i] + good[i]

        res = []
        needed = k - 1

        for i in range(n - k + 1):
            # Window nums[i..i+k-1] is valid iff all k-1 adjacent pairs are +1
            cnt = prefix[i + k - 1] - prefix[i]
            if cnt == needed:
                res.append(nums[i + k - 1])
            else:
                res.append(-1)

        return res

from typing import List

class Solution:
    def maximumValueSum(self, board: List[List[int]]) -> int:
        m, n = len(board), len(board[0])
        NEG = -10**30

        # top3_prefix[r][c1][c2]:
        # considering rows [0..r], best sum of placing 2 rooks on two distinct rows
        # using columns c1 and c2 (unordered pair, stored with c1 < c2)
        top3_prefix = []
        prev = [[NEG] * n for _ in range(n)]

        for r in range(m):
            cur = [row[:] for row in prev]
            row = board[r]
            for c1 in range(n):
                v1 = row[c1]
                for c2 in range(c1 + 1, n):
                    s = v1 + row[c2]
                    if s > cur[c1][c2]:
                        cur[c1][c2] = s
            top3_prefix.append(cur)
            prev = cur

        # best_suffix[r][c]:
        # considering rows [r..m-1], best value of placing 1 rook in column c
        best_suffix = [[NEG] * n for _ in range(m)]
        best = [NEG] * n
        for r in range(m - 1, -1, -1):
            for c in range(n):
                if board[r][c] > best[c]:
                    best[c] = board[r][c]
                best_suffix[r][c] = best[c]

        ans = NEG

        # Use middle row r for the single rook.
        # Pick 2 rooks from rows above r, and 1 rook from rows below r.
        for r in range(1, m - 1):
            pref = top3_prefix[r - 1]
            for mid_col in range(n):
                mid_val = board[r][mid_col]
                for c1 in range(n):
                    if c1 == mid_col:
                        continue
                    for c2 in range(c1 + 1, n):
                        if c2 == mid_col:
                            continue
                        pair_sum = pref[c1][c2]
                        if pair_sum == NEG:
                            continue
                        total = pair_sum + mid_val
                        # invalid: pair uses c1,c2, middle uses mid_col, all distinct already
                        # Need one more rook below? Actually pair above + middle = 3 rooks? No:
                        # pair above already has 2 rooks, middle adds 1 => total 3 rooks.
                        # This already satisfies conditions.
                        ans = max(ans, total)

        # Also need to handle all 3 rooks on arbitrary 3 rows, not necessarily with 2 above and 1 at middle.
        # Simpler complete approach:
        # choose middle row r, one rook on it, one above, one below.
        # pre1[r][c] = best above row r in column c
        pre1 = [[NEG] * n for _ in range(m)]
        best = [NEG] * n
        for r in range(m):
            pre1[r] = best[:]
            for c in range(n):
                if board[r][c] > best[c]:
                    best[c] = board[r][c]

        suf1 = [[NEG] * n for _ in range(m)]
        best = [NEG] * n
        for r in range(m - 1, -1, -1):
            suf1[r] = best[:]
            for c in range(n):
                if board[r][c] > best[c]:
                    best[c] = board[r][c]

        # For each row as middle, choose distinct columns a, b, c:
        # one above in a, middle in b, one below in c
        # maximize pre1[r][a] + board[r][b] + suf1[r][c]
        # with a, b, c distinct.
        for r in range(1, m - 1):
            # top candidates from above and below are enough if we keep several best columns,
            # but n <= 100 so O(n^3) per row is acceptable? 100^4 too much.
            # Instead for each middle column b, try all a and derive best c.
            for b in range(n):
                mid = board[r][b]
                for a in range(n):
                    if a == b or pre1[r][a] == NEG:
                        continue
                    best_c = NEG
                    for c in range(n):
                        if c != a and c != b and suf1[r][c] > best_c:
                            best_c = suf1[r][c]
                    if best_c != NEG:
                        ans = max(ans, pre1[r][a] + mid + best_c)

        # Also consider configurations where all 3 chosen rows are all above/below any split,
        # by direct DP over rows:
        # dp[k][mask-columns impossible] is not feasible for n=100.
        # Since only 3 rooks are needed, enumerate row triples and solve best matching.
        # O(m^3 * n^3) too much. Instead use row-combination with top columns.
        #
        # Key observation: for any set of 3 rows, only top 3 columns per row matter enough
        # to determine the optimal distinct-column assignment among 3 rows.
        # We keep top 3 entries of each row, enumerate row triples, and all assignments.
        top_cols = []
        for r in range(m):
            cols = sorted(range(n), key=lambda c: board[r][c], reverse=True)[:3]
            top_cols.append(cols)

        for i in range(m):
            for j in range(i + 1, m):
                for k in range(j + 1, m):
                    for c1 in top_cols[i]:
                        for c2 in top_cols[j]:
                            if c2 == c1:
                                continue
                            for c3 in top_cols[k]:
                                if c3 == c1 or c3 == c2:
                                    continue
                                ans = max(ans, board[i][c1] + board[j][c2] + board[k][c3])

        return ans

from typing import List
from itertools import combinations

class Solution:
    def maximumValueSum(self, board: List[List[int]]) -> int:
        m, n = len(board), len(board[0])
        NEG = -10**30

        # For each row, keep only its top 3 cells: (value, col).
        # In any optimal placement of 3 rooks, if a row is used, the chosen cell
        # must be among that row's top 3 values, since at most 2 columns are blocked
        # by the other two rooks.
        row_top = []
        for i in range(m):
            best = []
            for j, v in enumerate(board[i]):
                best.append((v, j))
            best.sort(reverse=True)
            row_top.append(best[:3])

        ans = NEG

        # Choose 3 distinct rows, then try all combinations of candidates from
        # the top-3 cells of each chosen row, requiring distinct columns.
        for r1, r2, r3 in combinations(range(m), 3):
            for v1, c1 in row_top[r1]:
                for v2, c2 in row_top[r2]:
                    if c2 == c1:
                        continue
                    for v3, c3 in row_top[r3]:
                        if c3 == c1 or c3 == c2:
                            continue
                        ans = max(ans, v1 + v2 + v3)

        return ans

class Solution:
    def countKConstraintSubstrings(self, s: str, k: int) -> int:
        n = len(s)
        ans = 0

        for i in range(n):
            zeros = 0
            ones = 0
            for j in range(i, n):
                if s[j] == '0':
                    zeros += 1
                else:
                    ones += 1

                if zeros <= k or ones <= k:
                    ans += 1

        return ans

class Solution:
    def largestPalindrome(self, n: int, k: int) -> str:
        # For k in [1..9], the divisibility constraints are simple enough
        # to construct the lexicographically largest n-digit palindrome directly.

        if k == 1 or k == 3 or k == 9:
            return "9" * n

        if k == 2:
            if n == 1:
                return "8"
            s = ["9"] * n
            s[0] = s[-1] = "8"
            return "".join(s)

        if k == 5:
            if n == 1:
                return "5"
            s = ["9"] * n
            s[0] = s[-1] = "5"
            return "".join(s)

        if k == 4:
            if n == 1:
                return "8"
            if n == 2:
                return "88"
            s = ["9"] * n
            s[0] = s[1] = s[-2] = s[-1] = "8"
            return "".join(s)

        if k == 8:
            if n == 1:
                return "8"
            if n == 2:
                return "88"
            if n == 3:
                return "888"
            s = ["9"] * n
            s[0] = s[1] = s[2] = s[-3] = s[-2] = s[-1] = "8"
            return "".join(s)

        if k == 6:
            # Need divisible by 2 and 3.
            # Make ends even; maximize lexicographically.
            # Sum of digits must be divisible by 3.
            if n == 1:
                return "6"
            if n == 2:
                return "66"

            s = ["9"] * n
            s[0] = s[-1] = "8"  # ensure divisible by 2

            if n % 2 == 1:
                # Current sum = 8+8 + 9*(n-2) = 9n - 2 ≡ 1 (mod 3)
                # Reduce center by 1: 9 -> 8
                s[n // 2] = "8"
            else:
                # Current sum ≡ 1 (mod 3)
                # Reduce middle pair by 2 total: 9,9 -> 8,8
                s[n // 2 - 1] = s[n // 2] = "8"
            return "".join(s)

        # k == 7
        # Use modular arithmetic on the first half to construct the largest palindrome.
        m = (n + 1) // 2

        pow10 = [1] * n
        for i in range(1, n):
            pow10[i] = (pow10[i - 1] * 10) % 7

        # weight of digit placed at position i in first half
        weights = [0] * m
        for i in range(m):
            j = n - 1 - i
            if i == j:
                weights[i] = pow10[i] % 7
            else:
                weights[i] = (pow10[i] + pow10[j]) % 7

        # suffix reachability:
        # can[i][r] = whether using positions i..m-1 we can achieve remainder r
        can = [[False] * 7 for _ in range(m + 1)]
        can[m][0] = True

        for i in range(m - 1, -1, -1):
            for r in range(7):
                w = weights[i]
                start = 1 if i == 0 else 0
                ok = False
                for d in range(start, 10):
                    nr = (r - d * w) % 7
                    if can[i + 1][nr]:
                        ok = True
                        break
                can[i][r] = ok

        res = []
        cur = 0
        for i in range(m):
            w = weights[i]
            start = 1 if i == 0 else 0
            for d in range(9, start - 1, -1):
                nxt = (cur + d * w) % 7
                need = (-nxt) % 7
                if can[i + 1][need]:
                    res.append(str(d))
                    cur = nxt
                    break

        first_half = res
        if n % 2 == 0:
            return "".join(first_half + first_half[::-1])
        else:
            return "".join(first_half + first_half[:-1][::-1])

class Solution:
    def getFinalState(self, nums: List[int], k: int, multiplier: int) -> List[int]:
        for _ in range(k):
            min_idx = 0
            for i in range(1, len(nums)):
                if nums[i] < nums[min_idx]:
                    min_idx = i
            nums[min_idx] *= multiplier
        return nums

class Solution:
    def countPairs(self, nums: List[int]) -> int:
        def almost_equal(x: int, y: int) -> bool:
            sx, sy = str(x), str(y)
            n = max(len(sx), len(sy))

            # Pad with leading zeros since leading zeros are allowed after swap
            sx = sx.zfill(n)
            sy = sy.zfill(n)

            # Already equal
            if sx == sy:
                return True

            diff = []
            for i in range(n):
                if sx[i] != sy[i]:
                    diff.append(i)

            # With at most one swap in one number, mismatches must be exactly 2
            if len(diff) != 2:
                return False

            i, j = diff

            # Swap in sx
            tx = list(sx)
            tx[i], tx[j] = tx[j], tx[i]
            if "".join(tx) == sy:
                return True

            # Swap in sy
            ty = list(sy)
            ty[i], ty[j] = ty[j], ty[i]
            return "".join(ty) == sx

        ans = 0
        n = len(nums)
        for i in range(n):
            for j in range(i + 1, n):
                if almost_equal(nums[i], nums[j]):
                    ans += 1
        return ans

class Solution:
    def generateKey(self, num1: int, num2: int, num3: int) -> int:
        a = str(num1).zfill(4)
        b = str(num2).zfill(4)
        c = str(num3).zfill(4)

        key = ''.join(str(min(int(a[i]), int(b[i]), int(c[i]))) for i in range(4))
        return int(key)

class Solution:
    def stringHash(self, s: str, k: int) -> str:
        res = []

        for i in range(0, len(s), k):
            total = 0
            for ch in s[i:i + k]:
                total += ord(ch) - ord('a')
            res.append(chr((total % 26) + ord('a')))

        return ''.join(res)

class Solution:
    def countGoodIntegers(self, n: int, k: int) -> int:
        from math import factorial

        half = (n + 1) // 2
        start = 10 ** (half - 1)
        end = 10 ** half

        def make_pal(first_half: int) -> int:
            s = str(first_half)
            if n % 2 == 0:
                return int(s + s[::-1])
            return int(s + s[-2::-1])

        def count_permutations(cnt):
            total = factorial(n)
            for v in cnt:
                total //= factorial(v)

            if cnt[0] == 0:
                return total

            bad = factorial(n - 1)
            for d in range(10):
                use = cnt[d] - (1 if d == 0 else 0)
                bad //= factorial(use)
            return total - bad

        seen = set()
        ans = 0

        for first_half in range(start, end):
            pal = make_pal(first_half)
            if pal % k != 0:
                continue

            cnt = [0] * 10
            for ch in str(pal):
                cnt[ord(ch) - 48] += 1

            key = tuple(cnt)
            if key in seen:
                continue
            seen.add(key)

            ans += count_permutations(cnt)

        return ans

class Solution:
    def checkTwoChessboards(self, coordinate1: str, coordinate2: str) -> bool:
        def color(coord: str) -> int:
            col = ord(coord[0]) - ord('a')
            row = ord(coord[1]) - ord('1')
            return (col + row) % 2

        return color(coordinate1) == color(coordinate2)

from typing import List
import heapq

class Solution:
    def resultsArray(self, queries: List[List[int]], k: int) -> List[int]:
        max_heap = []
        results = []

        for x, y in queries:
            dist = abs(x) + abs(y)

            heapq.heappush(max_heap, -dist)

            if len(max_heap) > k:
                heapq.heappop(max_heap)

            if len(max_heap) < k:
                results.append(-1)
            else:
                results.append(-max_heap[0])

        return results

from typing import List
from functools import lru_cache

class Solution:
    def maxScore(self, grid: List[List[int]]) -> int:
        m = len(grid)

        value_to_rows = {}
        for r, row in enumerate(grid):
            for v in set(row):
                if v not in value_to_rows:
                    value_to_rows[v] = []
                value_to_rows[v].append(r)

        values = sorted(value_to_rows.keys())
        n = len(values)

        @lru_cache(None)
        def dp(i: int, mask: int) -> int:
            if i == n:
                return 0

            res = dp(i + 1, mask)
            v = values[i]

            for r in value_to_rows[v]:
                if not (mask & (1 << r)):
                    res = max(res, v + dp(i + 1, mask | (1 << r)))

            return res

        return dp(0, 0)

from typing import List

class Solution:
    def maximumSubarrayXor(self, nums: List[int], queries: List[List[int]]) -> List[int]:
        n = len(nums)

        # score[i][j] = XOR score of subarray nums[i..j]
        score = [[0] * n for _ in range(n)]

        for i in range(n):
            score[i][i] = nums[i]

        # From the operation definition:
        # score(i, j) = score(i, j-1) XOR score(i+1, j)
        for length in range(2, n + 1):
            for i in range(n - length + 1):
                j = i + length - 1
                score[i][j] = score[i][j - 1] ^ score[i + 1][j]

        # best[i][j] = maximum XOR score among all subarrays inside nums[i..j]
        best = [[0] * n for _ in range(n)]

        for i in range(n):
            best[i][i] = nums[i]

        for length in range(2, n + 1):
            for i in range(n - length + 1):
                j = i + length - 1
                best[i][j] = max(score[i][j], best[i][j - 1], best[i + 1][j])

        return [best[l][r] for l, r in queries]

class Solution:
    def convertDateToBinary(self, date: str) -> str:
        year, month, day = date.split('-')
        return f"{bin(int(year))[2:]}-{bin(int(month))[2:]}-{bin(int(day))[2:]}"

class Solution:
    def maxPossibleScore(self, start: List[int], d: int) -> int:
        start.sort()
        n = len(start)

        def can(score: int) -> bool:
            prev = start[0]
            for i in range(1, n):
                cur = max(start[i], prev + score)
                if cur > start[i] + d:
                    return False
                prev = cur
            return True

        left, right = 0, start[-1] + d - start[0] + 1
        while left + 1 < right:
            mid = (left + right) // 2
            if can(mid):
                left = mid
            else:
                right = mid
        return left

class Solution:
    def findMaximumScore(self, nums: List[int]) -> int:
        n = len(nums)
        ans = 0
        best = nums[0]

        for i in range(1, n):
            ans += best
            best = max(best, nums[i])

        return ans

from typing import List
from collections import deque
from functools import lru_cache

class Solution:
    def maxMoves(self, kx: int, ky: int, positions: List[List[int]]) -> int:
        pts = [(kx, ky)] + [tuple(p) for p in positions]
        n = len(positions)
        dirs = [(2, 1), (2, -1), (-2, 1), (-2, -1),
                (1, 2), (1, -2), (-1, 2), (-1, -2)]

        def bfs(sx: int, sy: int):
            dist = [[-1] * 50 for _ in range(50)]
            q = deque([(sx, sy)])
            dist[sx][sy] = 0
            while q:
                x, y = q.popleft()
                for dx, dy in dirs:
                    nx, ny = x + dx, y + dy
                    if 0 <= nx < 50 and 0 <= ny < 50 and dist[nx][ny] == -1:
                        dist[nx][ny] = dist[x][y] + 1
                        q.append((nx, ny))
            return dist

        # pairwise distances between start/pawns
        m = n + 1
        d = [[0] * m for _ in range(m)]
        all_dist = [bfs(x, y) for x, y in pts]
        for i in range(m):
            for j in range(m):
                x, y = pts[j]
                d[i][j] = all_dist[i][x][y]

        @lru_cache(None)
        def dp(mask: int, cur: int, turn: int) -> int:
            if mask == (1 << n) - 1:
                return 0

            if turn == 0:  # Alice maximizes
                best = 0
                for i in range(n):
                    if not (mask >> i) & 1:
                        best = max(best, d[cur][i + 1] + dp(mask | (1 << i), i + 1, 1))
                return best
            else:  # Bob minimizes
                best = float('inf')
                for i in range(n):
                    if not (mask >> i) & 1:
                        best = min(best, d[cur][i + 1] + dp(mask | (1 << i), i + 1, 0))
                return best

        return dp(0, 0, 0)

class Solution:
    def stableMountains(self, height: List[int], threshold: int) -> List[int]:
        res = []
        for i in range(1, len(height)):
            if height[i - 1] > threshold:
                res.append(i)
        return res

from typing import List
from collections import deque

class Solution:
    def findSafeWalk(self, grid: List[List[int]], health: int) -> bool:
        m, n = len(grid), len(grid[0])

        # dist[i][j] = minimum health loss needed to reach (i, j)
        dist = [[float('inf')] * n for _ in range(m)]
        dist[0][0] = grid[0][0]

        dq = deque([(0, 0)])
        directions = [(1, 0), (-1, 0), (0, 1), (0, -1)]

        while dq:
            x, y = dq.popleft()

            for dx, dy in directions:
                nx, ny = x + dx, y + dy
                if 0 <= nx < m and 0 <= ny < n:
                    new_cost = dist[x][y] + grid[nx][ny]
                    if new_cost < dist[nx][ny]:
                        dist[nx][ny] = new_cost
                        if grid[nx][ny] == 0:
                            dq.appendleft((nx, ny))
                        else:
                            dq.append((nx, ny))

        return dist[m - 1][n - 1] < health

class Solution:
    def maxValue(self, nums: List[int], k: int) -> int:
        n = len(nums)
        MAXV = 128  # nums[i] < 2^7

        # left[i]: possible OR values by choosing exactly k elements from nums[0..i]
        left = [set() for _ in range(n)]
        dp = [set() for _ in range(k + 1)]
        dp[0].add(0)

        for i, x in enumerate(nums):
            ndp = [set(s) for s in dp]
            for cnt in range(k):
                for v in dp[cnt]:
                    ndp[cnt + 1].add(v | x)
            dp = ndp
            left[i] = set(dp[k])

        # right[i]: possible OR values by choosing exactly k elements from nums[i..n-1]
        right = [set() for _ in range(n)]
        dp = [set() for _ in range(k + 1)]
        dp[0].add(0)

        for i in range(n - 1, -1, -1):
            x = nums[i]
            ndp = [set(s) for s in dp]
            for cnt in range(k):
                for v in dp[cnt]:
                    ndp[cnt + 1].add(v | x)
            dp = ndp
            right[i] = set(dp[k])

        ans = 0
        # split between i and i+1:
        # choose k from nums[0..i], and k from nums[i+1..n-1]
        for i in range(k - 1, n - k):
            for a in left[i]:
                for b in right[i + 1]:
                    ans = max(ans, a ^ b)

        return ans

from typing import List
import bisect

class Solution:
    def maxPathLength(self, coordinates: List[List[int]], k: int) -> int:
        xk, yk = coordinates[k]

        left = []
        right = []

        for x, y in coordinates:
            if x < xk and y < yk:
                left.append((x, y))
            elif x > xk and y > yk:
                right.append((x, y))

        def lis_2d(points: List[tuple]) -> int:
            if not points:
                return 0

            points.sort(key=lambda p: (p[0], -p[1]))
            tails = []

            for _, y in points:
                pos = bisect.bisect_left(tails, y)
                if pos == len(tails):
                    tails.append(y)
                else:
                    tails[pos] = y

            return len(tails)

        return lis_2d(left) + 1 + lis_2d(right)

class Solution:
    def getSneakyNumbers(self, nums: List[int]) -> List[int]:
        seen = set()
        ans = []

        for num in nums:
            if num in seen:
                ans.append(num)
            else:
                seen.add(num)

        return ans

class Solution:
    def minValidStrings(self, words: List[str], target: str) -> int:
        n = len(target)

        # Build trie of all words. Any node on a path from root represents
        # a valid prefix of some word.
        trie = {}
        END = "#"
        for w in words:
            node = trie
            for ch in w:
                if ch not in node:
                    node[ch] = {}
                node = node[ch]
            node[END] = True

        # dp[i] = minimum number of valid strings to form target[:i]
        INF = 10**9
        dp = [INF] * (n + 1)
        dp[0] = 0

        for i in range(n):
            if dp[i] == INF:
                continue

            node = trie
            j = i
            while j < n and target[j] in node:
                node = node[target[j]]
                j += 1
                # Every traversed prefix is valid
                if dp[j] > dp[i] + 1:
                    dp[j] = dp[i] + 1

        return dp[n] if dp[n] != INF else -1

class Solution:
    def minValidStrings(self, words: List[str], target: str) -> int:
        n = len(target)

        # Build trie of words so every trie node represents a valid prefix.
        trie = {}
        for w in words:
            node = trie
            for ch in w:
                if ch not in node:
                    node[ch] = {}
                node = node[ch]

        # For each position i, compute the farthest index reachable by taking
        # one valid string starting at i.
        farthest = [i for i in range(n)]
        for i in range(n):
            node = trie
            j = i
            while j < n and target[j] in node:
                node = node[target[j]]
                j += 1
                farthest[i] = j

        # Greedy minimum jumps on intervals [i, farthest[i])
        ans = 0
        cur_end = 0
        next_end = 0
        i = 0

        while cur_end < n:
            while i < cur_end + 1 and i < n:
                next_end = max(next_end, farthest[i])
                i += 1
            if next_end <= cur_end:
                return -1
            ans += 1
            cur_end = next_end

        return ans

class Solution:
    def reportSpam(self, message: List[str], bannedWords: List[str]) -> bool:
        banned = set(bannedWords)
        count = 0

        for word in message:
            if word in banned:
                count += 1
                if count >= 2:
                    return True

        return False

from typing import List
import math

class Solution:
    def minNumberOfSeconds(self, mountainHeight: int, workerTimes: List[int]) -> int:
        def can_finish(t: int) -> bool:
            total = 0
            for w in workerTimes:
                # Maximum x such that:
                # w * x * (x + 1) // 2 <= t
                # x^2 + x - 2t/w <= 0
                val = (2 * t) // w
                x = (math.isqrt(1 + 4 * val) - 1) // 2
                total += x
                if total >= mountainHeight:
                    return True
            return False

        left, right = 0, min(workerTimes) * mountainHeight * (mountainHeight + 1) // 2

        while left < right:
            mid = (left + right) // 2
            if can_finish(mid):
                right = mid
            else:
                left = mid + 1

        return left

class Solution:
    def validSubstringCount(self, word1: str, word2: str) -> int:
        need = [0] * 26
        for ch in word2:
            need[ord(ch) - ord('a')] += 1

        window = [0] * 26
        missing = len(word2)
        left = 0
        ans = 0
        n = len(word1)

        for right, ch in enumerate(word1):
            idx = ord(ch) - ord('a')
            window[idx] += 1
            if window[idx] <= need[idx]:
                missing -= 1

            while missing == 0:
                ans += n - right
                left_idx = ord(word1[left]) - ord('a')
                if window[left_idx] <= need[left_idx]:
                    missing += 1
                window[left_idx] -= 1
                left += 1

        return ans

class Solution:
    def validSubstringCount(self, word1: str, word2: str) -> int:
        need = [0] * 26
        for ch in word2:
            need[ord(ch) - 97] += 1

        have = [0] * 26
        missing = len(word2)
        n = len(word1)
        ans = 0
        left = 0

        for right in range(n):
            idx = ord(word1[right]) - 97
            have[idx] += 1
            if have[idx] <= need[idx]:
                missing -= 1

            while missing == 0:
                left_idx = ord(word1[left]) - 97
                if have[left_idx] - 1 >= need[left_idx]:
                    have[left_idx] -= 1
                    left += 1
                else:
                    break

            if missing == 0:
                ans += left + 1

        return ans

class Solution:
    def minElement(self, nums: List[int]) -> int:
        def digit_sum(x: int) -> int:
            s = 0
            while x > 0:
                s += x % 10
                x //= 10
            return s

        return min(digit_sum(x) for x in nums)

class Solution:
    def maximumTotalSum(self, maximumHeight: List[int]) -> int:
        maximumHeight.sort(reverse=True)

        total = 0
        prev = float('inf')

        for h in maximumHeight:
            assign = min(h, prev - 1)
            if assign <= 0:
                return -1
            total += assign
            prev = assign

        return total

class Solution:
    def kthCharacter(self, k: int) -> str:
        # The character at position k depends on how many times we move to the
        # "generated/appended" half while tracing back to the original string.
        # This count equals the number of 1-bits in (k - 1).
        shifts = bin(k - 1).count("1")
        return chr((ord('a') - ord('a') + shifts) % 26 + ord('a'))

class Solution:
    def countOfSubstrings(self, word: str, k: int) -> int:
        vowels = set("aeiou")
        n = len(word)

        def count_at_most(limit: int) -> int:
            if limit < 0:
                return 0

            last = {v: -1 for v in vowels}
            left = 0
            consonants = 0
            ans = 0

            for right, ch in enumerate(word):
                if ch in vowels:
                    last[ch] = right
                else:
                    consonants += 1

                while consonants > limit:
                    if word[left] not in vowels:
                        consonants -= 1
                    left += 1

                min_last = min(last.values())
                if min_last >= left:
                    ans += min_last - left + 1

            return ans

        return count_at_most(k) - count_at_most(k - 1)

class Solution:
    def countOfSubstrings(self, word: str, k: int) -> int:
        vowels = {'a', 'e', 'i', 'o', 'u'}

        def count_at_most(limit: int) -> int:
            if limit < 0:
                return 0

            left = 0
            consonants = 0
            last = {v: -1 for v in vowels}
            res = 0

            for right, ch in enumerate(word):
                if ch in vowels:
                    last[ch] = right
                else:
                    consonants += 1

                while consonants > limit:
                    if word[left] not in vowels:
                        consonants -= 1
                    left += 1

                min_last = min(last.values())
                if min_last >= left:
                    res += min_last - left + 1

            return res

        return count_at_most(k) - count_at_most(k - 1)

class Solution:
    def kthCharacter(self, k: int, operations: List[int]) -> str:
        n = len(operations)

        lengths = [1]
        for _ in operations:
            lengths.append(lengths[-1] * 2)

        shift = 0
        cur_k = k

        for i in range(n - 1, -1, -1):
            half = lengths[i]
            if cur_k > half:
                cur_k -= half
                if operations[i] == 1:
                    shift += 1

        return chr((ord('a') - ord('a') + shift) % 26 + ord('a'))

class Solution:
    def maxGoodNumber(self, nums: List[int]) -> int:
        from itertools import permutations

        def bits(x: int) -> str:
            return bin(x)[2:]

        ans = 0
        for perm in permutations(nums):
            s = "".join(bits(x) for x in perm)
            ans = max(ans, int(s, 2))
        return ans

from typing import List
from collections import deque

class Solution:
    def remainingMethods(self, n: int, k: int, invocations: List[List[int]]) -> List[int]:
        graph = [[] for _ in range(n)]
        for a, b in invocations:
            graph[a].append(b)

        suspicious = [False] * n
        q = deque([k])
        suspicious[k] = True

        while q:
            u = q.popleft()
            for v in graph[u]:
                if not suspicious[v]:
                    suspicious[v] = True
                    q.append(v)

        for a, b in invocations:
            if not suspicious[a] and suspicious[b]:
                return list(range(n))

        return [i for i in range(n) if not suspicious[i]]

class Solution:
    def findXSum(self, nums: List[int], k: int, x: int) -> List[int]:
        n = len(nums)
        ans = []

        for i in range(n - k + 1):
            freq = {}
            for v in nums[i:i + k]:
                freq[v] = freq.get(v, 0) + 1

            # Sort by frequency descending, then value descending
            order = sorted(freq.items(), key=lambda p: (-p[1], -p[0]))

            total = 0
            for val, cnt in order[:x]:
                total += val * cnt

            ans.append(total)

        return ans

class Solution:
    def countWinningSequences(self, s: str) -> int:
        MOD = 10**9 + 7
        n = len(s)

        # 0 -> F, 1 -> W, 2 -> E
        mp = {'F': 0, 'W': 1, 'E': 2}
        alice = [mp[c] for c in s]

        def score(b, a):
            if b == a:
                return 0
            # F beats E, W beats F, E beats W
            if (b == 0 and a == 2) or (b == 1 and a == 0) or (b == 2 and a == 1):
                return 1
            return -1

        # dp[last][diff_shifted]
        # diff = Bob_score - Alice_score
        offset = n
        size = 2 * n + 1
        dp = [[0] * size for _ in range(3)]

        # First round
        for b in range(3):
            d = score(b, alice[0])
            dp[b][d + offset] = 1

        for i in range(1, n):
            ndp = [[0] * size for _ in range(3)]
            for last in range(3):
                row = dp[last]
                for idx in range(size):
                    cnt = row[idx]
                    if cnt == 0:
                        continue
                    diff = idx - offset
                    for b in range(3):
                        if b == last:
                            continue
                        nd = diff + score(b, alice[i])
                        ndp[b][nd + offset] = (ndp[b][nd + offset] + cnt) % MOD
            dp = ndp

        ans = 0
        for last in range(3):
            for idx in range(offset + 1, size):
                ans = (ans + dp[last][idx]) % MOD
        return ans

from typing import List

class Solution:
    def minConnectedGroups(self, intervals: List[List[int]], k: int) -> int:
        intervals.sort()

        merged = []
        for l, r in intervals:
            if not merged or l > merged[-1][1]:
                merged.append([l, r])
            else:
                merged[-1][1] = max(merged[-1][1], r)

        m = len(merged)
        if m == 1:
            return 1

        starts = [x[0] for x in merged]
        ends = [x[1] for x in merged]

        ans = m

        j = 0
        for i in range(m):
            if j < i:
                j = i

            # To connect group i through group j with one new interval [a, b],
            # we need b - a <= k and also overlap/touch every group in between.
            # Minimum needed length is starts[j] - ends[i].
            while j + 1 < m and starts[j + 1] - ends[i] <= k:
                j += 1

            connected = j - i + 1
            ans = min(ans, m - (connected - 1))

        return ans

from typing import List

class Solution:
    def stringSequence(self, target: str) -> List[str]:
        res = []
        cur = ""

        for ch in target:
            cur += "a"
            res.append(cur)

            steps = (ord(ch) - ord('a')) % 26
            for _ in range(steps):
                cur = cur[:-1] + chr((ord(cur[-1]) - ord('a') + 1) % 26 + ord('a'))
                res.append(cur)

        return res

class Solution:
    def numberOfSubstrings(self, s: str, k: int) -> int:
        n = len(s)

        if k == 1:
            return n * (n + 1) // 2

        ans = 0

        for i in range(n):
            freq = [0] * 26
            for j in range(i, n):
                idx = ord(s[j]) - ord('a')
                freq[idx] += 1
                if freq[idx] >= k:
                    ans += n - j
                    break

        return ans

class Solution:
    def minOperations(self, nums: List[int]) -> int:
        def smallest_prime_factor(x: int) -> int:
            if x % 2 == 0:
                return 2
            d = 3
            while d * d <= x:
                if x % d == 0:
                    return d
                d += 2
            return x

        ops = 0

        for i in range(len(nums) - 2, -1, -1):
            if nums[i] <= nums[i + 1]:
                continue

            new_val = smallest_prime_factor(nums[i])
            if new_val > nums[i + 1]:
                return -1

            nums[i] = new_val
            ops += 1

        return ops

class Solution:
    def numberOfSubstrings(self, s: str, k: int) -> int:
        n = len(s)

        if k == 1:
            return n * (n + 1) // 2

        cnt = [0] * 26
        left = 0
        ans = 0

        for right in range(n):
            idx = ord(s[right]) - ord('a')
            cnt[idx] += 1

            while cnt[idx] >= k:
                ans += n - right
                cnt[ord(s[left]) - ord('a')] -= 1
                left += 1

        return ans

class Solution:
    def maxScore(self, n: int, k: int, stayScore: List[List[int]], travelScore: List[List[int]]) -> int:
        # dp[city] = maximum score after the previous day, ending in `city`
        dp = [0] * n

        for day in range(k):
            new_dp = [0] * n

            for dest in range(n):
                # Option 1: stay in the same city
                best = dp[dest] + stayScore[day][dest]

                # Option 2: travel from any other city to dest
                for curr in range(n):
                    if curr != dest:
                        best = max(best, dp[curr] + travelScore[curr][dest])

                new_dp[dest] = best

            dp = new_dp

        return max(dp)

class Solution:
    def lengthAfterTransformations(self, s: str, t: int, nums: List[int]) -> int:
        MOD = 10**9 + 7
        N = 26

        def mat_mul(A, B):
            C = [[0] * N for _ in range(N)]
            for i in range(N):
                Ai = A[i]
                Ci = C[i]
                for k in range(N):
                    if Ai[k] == 0:
                        continue
                    aik = Ai[k]
                    Bk = B[k]
                    for j in range(N):
                        Ci[j] = (Ci[j] + aik * Bk[j]) % MOD
            return C

        def mat_pow(M, power):
            R = [[0] * N for _ in range(N)]
            for i in range(N):
                R[i][i] = 1
            while power:
                if power & 1:
                    R = mat_mul(R, M)
                M = mat_mul(M, M)
                power >>= 1
            return R

        # Transition matrix:
        # if cnt is current row vector of character counts,
        # next_cnt = cnt * T
        T = [[0] * N for _ in range(N)]
        for c in range(N):
            for step in range(1, nums[c] + 1):
                T[c][(c + step) % N] = (T[c][(c + step) % N] + 1) % MOD

        Tp = mat_pow(T, t)

        freq = [0] * N
        for ch in s:
            freq[ord(ch) - ord('a')] += 1

        ans = 0
        for i in range(N):
            if freq[i] == 0:
                continue
            row_sum = sum(Tp[i]) % MOD
            ans = (ans + freq[i] * row_sum) % MOD

        return ans

class Solution:
    def isBalanced(self, num: str) -> bool:
        even_sum = 0
        odd_sum = 0

        for i, ch in enumerate(num):
            digit = int(ch)
            if i % 2 == 0:
                even_sum += digit
            else:
                odd_sum += digit

        return even_sum == odd_sum

from typing import List
import heapq

class Solution:
    def minTimeToReach(self, moveTime: List[List[int]]) -> int:
        n, m = len(moveTime), len(moveTime[0])

        dist = [[float('inf')] * m for _ in range(n)]
        dist[0][0] = 0
        pq = [(0, 0, 0)]  # (time, row, col)

        directions = [(1, 0), (-1, 0), (0, 1), (0, -1)]

        while pq:
            t, i, j = heapq.heappop(pq)

            if (i, j) == (n - 1, m - 1):
                return t

            if t > dist[i][j]:
                continue

            for di, dj in directions:
                ni, nj = i + di, j + dj
                if 0 <= ni < n and 0 <= nj < m:
                    nt = max(t, moveTime[ni][nj]) + 1
                    if nt < dist[ni][nj]:
                        dist[ni][nj] = nt
                        heapq.heappush(pq, (nt, ni, nj))

        return -1

class Solution:
    def maxSizedArray(self, s: int) -> int:
        def sum_or_upto(n: int) -> int:
            """
            Returns sum_{0 <= j,k < n} (j | k)
            """
            total_pairs = n * n
            res = 0
            bit = 0
            while (1 << bit) < n:
                p = 1 << bit
                full = n // (p << 1)
                rem = n % (p << 1)
                cnt_zero = full * p + max(0, rem - p)
                cnt_one = n - cnt_zero
                # Number of pairs where this bit in (j | k) is 1
                pairs_with_bit = total_pairs - cnt_zero * cnt_zero
                res += pairs_with_bit * p
                bit += 1
            return res

        def total_sum(n: int) -> int:
            # sum_i i * sum_{j,k}(j|k)
            return (n * (n - 1) // 2) * sum_or_upto(n)

        lo, hi = 1, 1
        while total_sum(hi) <= s:
            hi <<= 1

        while lo < hi:
            mid = (lo + hi + 1) // 2
            if total_sum(mid) <= s:
                lo = mid
            else:
                hi = mid - 1
        return lo

class Solution:
    def smallestNumber(self, n: int, t: int) -> int:
        def digit_product(x: int) -> int:
            prod = 1
            for ch in str(x):
                prod *= int(ch)
            return prod

        while True:
            if digit_product(n) % t == 0:
                return n
            n += 1

class Solution:
    def hasIncreasingSubarrays(self, nums: List[int], k: int) -> bool:
        n = len(nums)

        # inc[i] = length of the strictly increasing contiguous segment
        # starting at index i
        inc = [1] * n
        for i in range(n - 2, -1, -1):
            if nums[i] < nums[i + 1]:
                inc[i] = inc[i + 1] + 1

        # Check adjacent subarrays [i..i+k-1] and [i+k..i+2k-1]
        for i in range(n - 2 * k + 1):
            if inc[i] >= k and inc[i + k] >= k:
                return True

        return False

class Solution:
    def minOperations(self, nums: List[int]) -> int:
        n = len(nums)
        ops = 0

        # Process from right to left.
        # If nums[i] != nums[i+1], we need one operation on prefix i+1
        # to adjust nums[i] without affecting elements to the right.
        for i in range(n - 2, -1, -1):
            if nums[i] != nums[i + 1]:
                ops += 1

        return ops

from typing import List

class Solution:
    def countValidSelections(self, nums: List[int]) -> int:
        total = sum(nums)
        ans = 0
        left_sum = 0

        for x in nums:
            if x == 0:
                diff = total - left_sum - left_sum
                if diff == 0:
                    ans += 2
                elif abs(diff) == 1:
                    ans += 1
            left_sum += x

        return ans

class Solution:
    def isZeroArray(self, nums: List[int], queries: List[List[int]]) -> bool:
        n = len(nums)
        diff = [0] * (n + 1)

        for l, r in queries:
            diff[l] += 1
            if r + 1 < n:
                diff[r + 1] -= 1

        coverage = 0
        for i in range(n):
            coverage += diff[i]
            if coverage < nums[i]:
                return False

        return True

class Solution:
    def minZeroArray(self, nums: List[int], queries: List[List[int]]) -> int:
        n = len(nums)
        m = len(queries)

        def can(k: int) -> bool:
            diff = [0] * (n + 1)
            for i in range(k):
                l, r, val = queries[i]
                diff[l] += val
                if r + 1 < n:
                    diff[r + 1] -= val

            curr = 0
            for i in range(n):
                curr += diff[i]
                if curr < nums[i]:
                    return False
            return True

        if all(x == 0 for x in nums):
            return 0

        if not can(m):
            return -1

        left, right = 0, m
        while left < right:
            mid = (left + right) // 2
            if can(mid):
                right = mid
            else:
                left = mid + 1
        return left

class Solution:
    def canAliceWin(self, n: int) -> bool:
        remove = 10
        alice_turn = True

        while n >= remove:
            n -= remove
            alice_turn = not alice_turn
            remove -= 1

        return not alice_turn

from typing import List
import heapq

class Solution:
    def maxRemoval(self, nums: List[int], queries: List[List[int]]) -> int:
        n = len(nums)
        queries.sort()

        available = []   # max-heap by right endpoint: store -r
        active = []      # min-heap of chosen right endpoints

        used = 0
        i = 0

        for pos in range(n):
            while i < len(queries) and queries[i][0] <= pos:
                heapq.heappush(available, -queries[i][1])
                i += 1

            while active and active[0] < pos:
                heapq.heappop(active)

            while len(active) < nums[pos]:
                while available and -available[0] < pos:
                    heapq.heappop(available)

                if not available:
                    return -1

                r = -heapq.heappop(available)
                heapq.heappush(active, r)
                used += 1

        return len(queries) - used

class Solution:
    def minimumSumSubarray(self, nums: List[int], l: int, r: int) -> int:
        n = len(nums)
        ans = float('inf')

        for size in range(l, r + 1):
            window_sum = sum(nums[:size])
            if window_sum > 0:
                ans = min(ans, window_sum)

            for i in range(size, n):
                window_sum += nums[i] - nums[i - size]
                if window_sum > 0:
                    ans = min(ans, window_sum)

        return ans if ans != float('inf') else -1

class Solution:
    def isPossibleToRearrange(self, s: str, t: str, k: int) -> bool:
        n = len(s)
        size = n // k

        count = {}

        for i in range(0, n, size):
            part = s[i:i + size]
            count[part] = count.get(part, 0) + 1

        for i in range(0, n, size):
            part = t[i:i + size]
            if part not in count or count[part] == 0:
                return False
            count[part] -= 1

        return True

class Solution:
    def smallestNumber(self, n: int) -> int:
        x = 1
        while x < n:
            x = (x << 1) | 1
        return x

from typing import List
from collections import Counter

class Solution:
    def getLargestOutlier(self, nums: List[int]) -> int:
        total = sum(nums)
        freq = Counter(nums)
        ans = -10**18

        for x in nums:
            remaining = total - x
            if remaining % 2 != 0:
                continue

            s = remaining // 2  # candidate sum element

            # Need an index for sum element distinct from outlier's index
            if s == x:
                if freq[s] < 2:
                    continue
            else:
                if freq[s] == 0:
                    continue

            ans = max(ans, x)

        return ans

class Solution:
    def minOperations(self, nums: List[int], k: int) -> int:
        # If any number is already below k, we can never increase it.
        if any(x < k for x in nums):
            return -1

        # Each operation can reduce the current maximum value(s) to a chosen
        # valid h, which effectively removes one distinct value level above k.
        return len(set(x for x in nums if x > k))

from typing import List
from functools import lru_cache
import math

class Solution:
    def findMinimumTime(self, strength: List[int], k: int) -> int:
        n = len(strength)

        @lru_cache(None)
        def dp(mask: int) -> int:
            broken = mask.bit_count()
            if broken == n:
                return 0

            x = 1 + broken * k
            ans = float('inf')

            for i in range(n):
                if not (mask >> i) & 1:
                    # Minutes needed so that energy >= strength[i]
                    need = (strength[i] + x - 1) // x
                    ans = min(ans, need + dp(mask | (1 << i)))

            return ans

        return dp(0)

import heapq

class Solution:
    def minOperations(self, n: int, m: int) -> int:
        s = str(n)
        t = str(m)
        if len(s) != len(t):
            return -1

        L = len(s)
        limit = 10 ** L

        def sieve(mx: int):
            is_prime = [True] * mx
            if mx > 0:
                is_prime[0] = False
            if mx > 1:
                is_prime[1] = False
            p = 2
            while p * p < mx:
                if is_prime[p]:
                    for x in range(p * p, mx, p):
                        is_prime[x] = False
                p += 1
            return is_prime

        is_prime = sieve(limit)

        if is_prime[n] or is_prime[m]:
            return -1

        dist = {}
        dist[n] = n
        pq = [(n, n)]  # (cost, value)

        while pq:
            cost, x = heapq.heappop(pq)
            if x == m:
                return cost
            if cost != dist.get(x):
                continue

            digits = list(str(x).zfill(L))

            for i in range(L):
                d = ord(digits[i]) - ord('0')

                if d < 9:
                    ndigits = digits[:]
                    ndigits[i] = chr(ord('0') + d + 1)
                    y = int(''.join(ndigits))
                    if not is_prime[y]:
                        new_cost = cost + y
                        if new_cost < dist.get(y, float('inf')):
                            dist[y] = new_cost
                            heapq.heappush(pq, (new_cost, y))

                if d > 0:
                    ndigits = digits[:]
                    ndigits[i] = chr(ord('0') + d - 1)
                    y = int(''.join(ndigits))
                    if not is_prime[y]:
                        new_cost = cost + y
                        if new_cost < dist.get(y, float('inf')):
                            dist[y] = new_cost
                            heapq.heappush(pq, (new_cost, y))

        return -1

from typing import List
from math import gcd


class DSU:
    def __init__(self, n: int):
        self.p = list(range(n))
        self.sz = [1] * n

    def find(self, x: int) -> int:
        while self.p[x] != x:
            self.p[x] = self.p[self.p[x]]
            x = self.p[x]
        return x

    def union(self, a: int, b: int) -> bool:
        ra, rb = self.find(a), self.find(b)
        if ra == rb:
            return False
        if self.sz[ra] < self.sz[rb]:
            ra, rb = rb, ra
        self.p[rb] = ra
        self.sz[ra] += self.sz[rb]
        return True


class Solution:
    def countComponents(self, nums: List[int], threshold: int) -> int:
        n = len(nums)
        dsu = DSU(n)

        # Numbers greater than threshold cannot connect to anything:
        # lcm(a, b) >= max(a, b) > threshold.
        components = sum(1 for x in nums if x > threshold)

        small = [x for x in nums if x <= threshold]
        components += len(small)
        if not small:
            return components

        # Map value -> index in nums for values <= threshold
        idx = {}
        for i, x in enumerate(nums):
            if x <= threshold:
                idx[x] = i

        # For each divisor g, collect all nums values that are multiples of g.
        # If for two values a = g*x and b = g*y we have x*y <= threshold/g and gcd(x,y)=1,
        # then lcm(a,b) = g*x*y <= threshold, so they should be connected.
        #
        # We process all existing multiples of each g, reduced by g, and connect pairs
        # whose coprime reduced product fits the limit.
        present = [False] * (threshold + 1)
        for x in small:
            present[x] = True

        multiples = [[] for _ in range(threshold + 1)]
        for g in range(1, threshold + 1):
            for m in range(g, threshold + 1, g):
                if present[m]:
                    multiples[g].append(m // g)

        for g in range(1, threshold + 1):
            arr = multiples[g]
            if len(arr) <= 1:
                continue
            arr.sort()
            limit = threshold // g

            # Connect valid pairs
            k = len(arr)
            for i in range(k):
                x = arr[i]
                if x * x > limit and i + 1 < k:
                    # Since arr is sorted, for larger y, x*y only increases.
                    break
                a_val = g * x
                a_idx = idx[a_val]
                for j in range(i + 1, k):
                    y = arr[j]
                    if x * y > limit:
                        break
                    if gcd(x, y) == 1:
                        b_val = g * y
                        if dsu.union(a_idx, idx[b_val]):
                            components -= 1

        return components

