        return result

class Solution:
    def maxRectangleArea(self, points: List[List[int]]) -> int:
        n = len(points)
        pts = [tuple(p) for p in points]
        point_set = set(pts)
        ans = -1

        for i in range(n):
            x1, y1 = pts[i]
            for j in range(i + 1, n):
                x2, y2 = pts[j]

                # Use diagonal points of an axis-parallel rectangle
                if x1 == x2 or y1 == y2:
                    continue

                if (x1, y2) not in point_set or (x2, y1) not in point_set:
                    continue

                left, right = sorted((x1, x2))
                bottom, top = sorted((y1, y2))

                valid = True
                for x, y in pts:
                    # Skip the four corners
                    if (x, y) in {
                        (left, bottom),
                        (left, top),
                        (right, bottom),
                        (right, top),
                    }:
                        continue

                    # Any other point inside or on border invalidates the rectangle
                    if left <= x <= right and bottom <= y <= top:
                        valid = False
                        break

                if valid:
                    area = (right - left) * (top - bottom)
                    ans = max(ans, area)

        return ans

from typing import List
import sys

class Solution:
    def minRunesToAdd(self, n: int, crystals: List[int], flowFrom: List[int], flowTo: List[int]) -> int:
        sys.setrecursionlimit(1 << 20)

        graph = [[] for _ in range(n)]
        rev = [[] for _ in range(n)]
        for u, v in zip(flowFrom, flowTo):
            graph[u].append(v)
            rev[v].append(u)

        crystal_set = set(crystals)

        # Kosaraju: first pass
        visited = [False] * n
        order = []

        def dfs1(u: int) -> None:
            visited[u] = True
            for v in graph[u]:
                if not visited[v]:
                    dfs1(v)
            order.append(u)

        for i in range(n):
            if not visited[i]:
                dfs1(i)

        # Kosaraju: second pass
        comp = [-1] * n
        comp_count = 0

        def dfs2(u: int, cid: int) -> None:
            comp[u] = cid
            for v in rev[u]:
                if comp[v] == -1:
                    dfs2(v, cid)

        for u in reversed(order):
            if comp[u] == -1:
                dfs2(u, comp_count)
                comp_count += 1

        # Build SCC DAG indegrees and mark components containing crystals
        indeg = [0] * comp_count
        has_crystal = [False] * comp_count

        for node in crystals:
            has_crystal[comp[node]] = True

        for u, v in zip(flowFrom, flowTo):
            cu, cv = comp[u], comp[v]
            if cu != cv:
                indeg[cv] += 1

        # Count source SCCs without any crystal
        ans = 0
        for cid in range(comp_count):
            if indeg[cid] == 0 and not has_crystal[cid]:
                ans += 1

        return ans

class Solution:
    def buttonWithLongestTime(self, events: List[List[int]]) -> int:
        longest_time = events[0][1]
        answer = events[0][0]

        for i in range(1, len(events)):
            duration = events[i][1] - events[i - 1][1]
            index = events[i][0]

            if duration > longest_time or (duration == longest_time and index < answer):
                longest_time = duration
                answer = index

        return answer

from typing import List
from collections import defaultdict, deque

class Solution:
    def maxAmount(self, initialCurrency: str, pairs1: List[List[str]], rates1: List[float], pairs2: List[List[str]], rates2: List[float]) -> float:
        def build_graph(pairs: List[List[str]], rates: List[float]):
            graph = defaultdict(list)
            for (u, v), r in zip(pairs, rates):
                graph[u].append((v, r))
                graph[v].append((u, 1.0 / r))
            return graph

        def compute_values(graph, start):
            values = {start: 1.0}
            q = deque([start])

            while q:
                cur = q.popleft()
                for nxt, rate in graph[cur]:
                    if nxt not in values:
                        values[nxt] = values[cur] * rate
                        q.append(nxt)
            return values

        g1 = build_graph(pairs1, rates1)
        g2 = build_graph(pairs2, rates2)

        day1_amounts = compute_values(g1, initialCurrency)

        answer = 1.0
        for currency, amt in day1_amounts.items():
            day2_values = compute_values(g2, currency)
            if initialCurrency in day2_values:
                answer = max(answer, amt * day2_values[initialCurrency])

        return answer

class Solution:
    def countSubarrays(self, nums: List[int]) -> int:
