            if nums[i] + nums[i + 2] == nums[i + 1] / 2:
                count += 1

        return count

from typing import List

class Solution:
    def countPathsWithXorValue(self, grid: List[List[int]], k: int) -> int:
        MOD = 10**9 + 7
        m, n = len(grid), len(grid[0])

        # dp[j][x] = number of ways to reach current row's cell j with xor x
        dp = [[0] * 16 for _ in range(n)]

        for i in range(m):
            new_dp = [[0] * 16 for _ in range(n)]
            for j in range(n):
                val = grid[i][j]

                if i == 0 and j == 0:
                    new_dp[j][val] = 1
                    continue

                # From top
                if i > 0:
                    for x in range(16):
                        cnt = dp[j][x]
                        if cnt:
                            new_dp[j][x ^ val] = (new_dp[j][x ^ val] + cnt) % MOD

                # From left
                if j > 0:
                    for x in range(16):
                        cnt = new_dp[j - 1][x]
                        if cnt:
                            new_dp[j][x ^ val] = (new_dp[j][x ^ val] + cnt) % MOD

            dp = new_dp

        return dp[n - 1][k]

class Solution:
    def checkValidCuts(self, n: int, rectangles: List[List[int]]) -> bool:
        def can_make_three_sections(intervals):
            intervals.sort()
            merged_count = 0
            cur_l = cur_r = -1

            for l, r in intervals:
                if cur_l == -1:
                    cur_l, cur_r = l, r
                elif l < cur_r:
                    cur_r = max(cur_r, r)
                else:
                    merged_count += 1
                    cur_l, cur_r = l, r

            if cur_l != -1:
                merged_count += 1

            return merged_count >= 3

        x_intervals = [(sx, ex) for sx, sy, ex, ey in rectangles]
        y_intervals = [(sy, ey) for sx, sy, ex, ey in rectangles]

        return can_make_three_sections(x_intervals) or can_make_three_sections(y_intervals)

class Solution:
    def minimumOperations(self, nums: List[int]) -> int:
