        for ops in range((n + 2) // 3 + 1):
            remaining = nums[ops * 3:]
            if len(remaining) == len(set(remaining)):
                return ops

        return 0

class Solution:
    def maxDistinctElements(self, nums: List[int], k: int) -> int:
        nums.sort()
        count = 0
        prev = -10**30

        for x in nums:
            low = x - k
            high = x + k

            chosen = max(low, prev + 1)
            if chosen <= high:
                count += 1
                prev = chosen

        return count

class Solution:
    def minLength(self, s: str, numOps: int) -> int:
        n = len(s)

        def can(limit: int) -> bool:
            # Special case: to make every run length <= 1, string must be alternating.
            if limit == 1:
                mismatches_start_0 = 0  # pattern: 0101...
                mismatches_start_1 = 0  # pattern: 1010...
                for i, ch in enumerate(s):
                    expected0 = '0' if i % 2 == 0 else '1'
                    expected1 = '1' if i % 2 == 0 else '0'
                    if ch != expected0:
                        mismatches_start_0 += 1
                    if ch != expected1:
                        mismatches_start_1 += 1
                return min(mismatches_start_0, mismatches_start_1) <= numOps

            # For limit >= 2, each original run can be handled independently.
            # A run of length L needs floor(L / (limit + 1)) flips.
            ops = 0
            run_len = 1
            for i in range(1, n):
                if s[i] == s[i - 1]:
                    run_len += 1
                else:
                    ops += run_len // (limit + 1)
                    if ops > numOps:
                        return False
                    run_len = 1
            ops += run_len // (limit + 1)
            return ops <= numOps

        left, right = 1, n
        while left < right:
            mid = (left + right) // 2
            if can(mid):
                right = mid
            else:
                left = mid + 1
        return left

class Solution:
    def minLength(self, s: str, numOps: int) -> int:
        n = len(s)

        def can_make_alternating() -> bool:
            # Cost to convert into pattern 0101...
            cost0 = 0
            # Cost to convert into pattern 1010...
            cost1 = 0
            for i, ch in enumerate(s):
                expected0 = '0' if i % 2 == 0 else '1'
                expected1 = '1' if i % 2 == 0 else '0'
                if ch != expected0:
                    cost0 += 1
                if ch != expected1:
                    cost1 += 1
            return min(cost0, cost1) <= numOps

        def can(limit: int) -> bool:
            # Check if every run can be reduced to length <= limit
            # using at most numOps flips.
            ops = 0
            i = 0
            while i < n:
                j = i
                while j < n and s[j] == s[i]:
                    j += 1
                run_len = j - i
                ops += run_len // (limit + 1)
                if ops > numOps:
                    return False
                i = j
            return ops <= numOps

        if can_make_alternating():
            return 1

        left, right = 2, n
        ans = n
        while left <= right:
            mid = (left + right) // 2
            if can(mid):
                ans = mid
                right = mid - 1
            else:
                left = mid + 1
        return ans

