from collections import defaultdict

class Solution:
    def maximumMatchingIndices(self, nums1: List[int], nums2: List[int]) -> int:
        n = len(nums1)

        pos2 = defaultdict(list)
        for i, x in enumerate(nums2):
            pos2[x].append(i)

        shifts = [0] * n

        for i, x in enumerate(nums1):
            for j in pos2[x]:
                k = (j - i) % n
                shifts[k] += 1

        return max(shifts)

class Solution:
    def minimumOperations(self, grid: List[List[int]]) -> int:
        m, n = len(grid), len(grid[0])
        ans = 0

        for j in range(n):
            prev = grid[0][j]
            for i in range(1, m):
                need = max(grid[i][j], prev + 1)
                ans += need - grid[i][j]
                prev = need

        return ans

class Solution:
    def answerString(self, word: str, numFriends: int) -> str:
        n = len(word)

        # If every friend must get exactly one character, all pieces are length 1.
        if numFriends == n:
            return max(word)

        # In any valid split into numFriends non-empty parts, a chosen piece can be
        # any substring whose length is at most:
        # n - (numFriends - 1)
        # because the remaining numFriends - 1 parts need at least one character each.
        max_len = n - numFriends + 1

        ans = ""
        for i in range(n):
            candidate = word[i:min(n, i + max_len)]
            if candidate > ans:
                ans = candidate

        return ans

class Solution:
    def countGoodArrays(self, n: int, m: int, k: int) -> int:
        MOD = 10**9 + 7

        # If exactly k adjacent pairs are equal, then among n-1 adjacent pairs,
        # the remaining (n-1-k) pairs must be different.
        # Choose which k positions are equal: C(n-1, k)
        # Choose first element: m ways
        # For each different-adjacent position, choose a value different from previous: (m-1) ways
        # Total = m * C(n-1, k) * (m-1)^(n-1-k)

        if k < 0 or k > n - 1:
            return 0

        def mod_pow(a, b):
            res = 1
            a %= MOD
            while b:
                if b & 1:
                    res = res * a % MOD
                a = a * a % MOD
                b >>= 1
            return res

        def mod_inv(x):
            return mod_pow(x, MOD - 2)

        # Compute C(n-1, k) modulo MOD
        fact = [1] * n
        for i in range(1, n):
            fact[i] = fact[i - 1] * i % MOD

        inv_fact = [1] * n
        inv_fact[n - 1] = mod_inv(fact[n - 1])
        for i in range(n - 2, -1, -1):
            inv_fact[i] = inv_fact[i + 1] * (i + 1) % MOD

        comb = fact[n - 1] * inv_fact[k] % MOD * inv_fact[n - 1 - k] % MOD
        return m * comb % MOD * mod_pow(m - 1, n - 1 - k) % MOD

class Solution:
    def answerString(self, word: str, numFriends: int) -> str:
        n = len(word)

        # If there is only one friend, the whole word is the only piece.
        if numFriends == 1:
            return word

        # In any valid split into numFriends non-empty parts, a chosen piece can have
        # length at most n - (numFriends - 1), since every other part needs at least 1 char.
        max_len = n - numFriends + 1

        ans = ""
        for i in range(n):
            candidate = word[i:min(n, i + max_len)]
            if candidate > ans:
                ans = candidate

        return ans

class Solution:
    def hasMatch(self, s: str, p: str) -> bool:
        i = p.index('*')
        left = p[:i]
        right = p[i + 1:]

        n = len(s)
        l_len = len(left)
        r_len = len(right)

        for start in range(n - l_len + 1):
            if s[start:start + l_len] != left:
                continue

            min_end = start + l_len
            max_pos = n - r_len

            for j in range(min_end, max_pos + 1):
                if s[j:j + r_len] == right:
                    return True

        return False

from typing import List
from math import gcd

class Solution:
    def maxLength(self, nums: List[int]) -> int:
        def lcm(a: int, b: int) -> int:
            return a // gcd(a, b) * b

        n = len(nums)
        ans = 1

        for i in range(n):
            cur_gcd = 0
            cur_lcm = 1
            cur_prod = 1

            for j in range(i, n):
                cur_prod *= nums[j]
                cur_gcd = nums[j] if cur_gcd == 0 else gcd(cur_gcd, nums[j])
                cur_lcm = lcm(cur_lcm, nums[j])

                if cur_prod == cur_gcd * cur_lcm:
                    ans = max(ans, j - i + 1)

        return ans

class Solution:
    def calculateScore(self, s: str) -> int:
        # For each character, keep a stack of unmarked indices seen so far.
        # When we see its mirror, we pair with the closest unmarked one,
        # which is the most recent index in that mirror's stack.
        stacks = [[] for _ in range(26)]
        score = 0

        for i, ch in enumerate(s):
            idx = ord(ch) - ord('a')
            mirror_idx = 25 - idx

            if stacks[mirror_idx]:
                j = stacks[mirror_idx].pop()
                score += i - j
            else:
                stacks[idx].append(i)

        return score

class Solution:
    def zigzagTraversal(self, grid: List[List[int]]) -> List[int]:
        result = []
        take = True
        rows, cols = len(grid), len(grid[0])

        for r in range(rows):
            if r % 2 == 0:
                for c in range(cols):
                    if take:
                        result.append(grid[r][c])
                    take = not take
            else:
                for c in range(cols - 1, -1, -1):
                    if take:
                        result.append(grid[r][c])
                    take = not take

        return result

class Solution:
    def maximumAmount(self, coins: List[List[int]]) -> int:
        m, n = len(coins), len(coins[0])
        NEG_INF = -10**18

        # dp[j][k] = maximum coins to reach current row at column j
        # using exactly k neutralizations so far
        dp = [[NEG_INF] * 3 for _ in range(n)]

        for i in range(m):
            new = [[NEG_INF] * 3 for _ in range(n)]
            for j in range(n):
                val = coins[i][j]

                # Gather transitions from top and left
                prev_states = []
                if i == 0 and j == 0:
                    prev_states.append([0, NEG_INF, NEG_INF])
                else:
                    if i > 0:
                        prev_states.append(dp[j])
                    if j > 0:
                        prev_states.append(new[j - 1])

                for prev in prev_states:
                    for used in range(3):
                        if prev[used] == NEG_INF:
                            continue

                        # Do not neutralize this cell
                        new[j][used] = max(new[j][used], prev[used] + val)

                        # Neutralize this robber cell if possible
                        if val < 0 and used < 2:
                            new[j][used + 1] = max(new[j][used + 1], prev[used])

            dp = new

        return max(dp[n - 1])

from typing import List
import heapq

class DualHeapMedianCost:
    def __init__(self):
        self.small = []   # max heap via negatives
        self.large = []   # min heap
        self.delayed = {}
        self.small_size = 0
        self.large_size = 0
        self.small_sum = 0
        self.large_sum = 0

    def _prune_small(self):
        while self.small:
            x = -self.small[0]
            if self.delayed.get(x, 0):
                heapq.heappop(self.small)
                self.delayed[x] -= 1
                if self.delayed[x] == 0:
                    del self.delayed[x]
            else:
                break

    def _prune_large(self):
        while self.large:
            x = self.large[0]
            if self.delayed.get(x, 0):
                heapq.heappop(self.large)
                self.delayed[x] -= 1
                if self.delayed[x] == 0:
                    del self.delayed[x]
            else:
                break

    def _rebalance(self):
        if self.small_size > self.large_size + 1:
            self._prune_small()
            x = -heapq.heappop(self.small)
            self.small_size -= 1
            self.small_sum -= x
            heapq.heappush(self.large, x)
            self.large_size += 1
            self.large_sum += x
            self._prune_small()
        elif self.small_size < self.large_size:
            self._prune_large()
            x = heapq.heappop(self.large)
            self.large_size -= 1
            self.large_sum -= x
            heapq.heappush(self.small, -x)
            self.small_size += 1
            self.small_sum += x
            self._prune_large()

    def add(self, x: int) -> None:
        if not self.small or x <= -self.small[0]:
            heapq.heappush(self.small, -x)
            self.small_size += 1
            self.small_sum += x
        else:
            heapq.heappush(self.large, x)
            self.large_size += 1
            self.large_sum += x
        self._rebalance()

    def remove(self, x: int) -> None:
        self.delayed[x] = self.delayed.get(x, 0) + 1
        if self.small and x <= -self.small[0]:
            self.small_size -= 1
            self.small_sum -= x
            if self.small and -self.small[0] == x:
                self._prune_small()
        else:
            self.large_size -= 1
            self.large_sum -= x
            if self.large and self.large[0] == x:
                self._prune_large()
        self._rebalance()

    def get_cost(self) -> int:
        self._prune_small()
        self._prune_large()
        median = -self.small[0]
        left_cost = median * self.small_size - self.small_sum
        right_cost = self.large_sum - median * self.large_size
        return left_cost + right_cost


class Solution:
    def minOperations(self, nums: List[int], k: int) -> int:
        dh = DualHeapMedianCost()

        for i in range(k):
            dh.add(nums[i])

        ans = dh.get_cost()

        for i in range(k, len(nums)):
            dh.add(nums[i])
            dh.remove(nums[i - k])
            ans = min(ans, dh.get_cost())

        return ans

class Solution:
    def maxAdjacentDistance(self, nums: List[int]) -> int:
        ans = 0
        n = len(nums)

        for i in range(n):
            ans = max(ans, abs(nums[i] - nums[(i + 1) % n]))

        return ans

class Solution:
    def subarraySum(self, nums: List[int]) -> int:
        prefix = [0]
        for x in nums:
            prefix.append(prefix[-1] + x)

        total = 0
        for i, x in enumerate(nums):
            start = max(0, i - x)
            total += prefix[i + 1] - prefix[start]

        return total

from typing import List

class Solution:
    def minCost(self, n: int, cost: List[List[int]]) -> int:
        m = n // 2
        INF = 10**18

        # dp[cl][cr]:
        # minimum cost after processing pairs up to i,
        # where:
        # - left house of current pair uses color cl
        # - right house of current pair uses color cr
        # Constraints enforced:
        # - cl != cr (mirror condition for this pair)
        # - consecutive left houses differ
        # - consecutive right houses differ
        dp = [[INF] * 3 for _ in range(3)]

        # First pair: houses 0 and n-1
        for cl in range(3):
            for cr in range(3):
                if cl != cr:
                    dp[cl][cr] = cost[0][cl] + cost[n - 1][cr]

        # Process remaining pairs: (i, n-1-i)
        for i in range(1, m):
            ndp = [[INF] * 3 for _ in range(3)]
            left_idx = i
            right_idx = n - 1 - i

            for pcl in range(3):
                for pcr in range(3):
                    if dp[pcl][pcr] == INF:
                        continue
                    base = dp[pcl][pcr]

                    for cl in range(3):
                        if cl == pcl:
                            continue  # adjacent on left side
                        for cr in range(3):
                            if cr == pcr:
                                continue  # adjacent on right side
                            if cl == cr:
                                continue  # mirror condition

                            val = base + cost[left_idx][cl] + cost[right_idx][cr]
                            if val < ndp[cl][cr]:
                                ndp[cl][cr] = val
            dp = ndp

        ans = INF
        for cl in range(3):
            for cr in range(3):
                ans = min(ans, dp[cl][cr])

        return ans

from typing import List

class Solution:
    def minUnlockedIndices(self, nums: List[int], locked: List[int]) -> int:
        n = len(nums)
        a = nums

        # Final sorted target counts
        c1 = a.count(1)
        c2 = a.count(2)
        # c3 = n - c1 - c2

        # A value 3 can never move right, so any 3 before the final 3-zone is impossible.
        for i in range(c1 + c2):
            if a[i] == 3:
                return -1

        # A value 1 can never move left, so any 1 after the final 1-zone is impossible.
        for i in range(c1, n):
            if a[i] == 1:
                return -1

        ans = 0

        # 2s that must move left across 1s:
        # in the first c1 positions, every 2 must cross all later 1s until it reaches 2-zone.
        # Each adjacent boundary used by such movement must be unlocked.
        need = 0  # number of pending 2s needing to cross current boundary
        for i in range(c1 - 1, -1, -1):
            if a[i] == 2:
                need += 1
            # boundary i separates i and i+1, used if there is any pending 2 and i < n-1
            if i < n - 1 and need > 0 and locked[i] == 1:
                ans += 1
            if a[i] == 1:
                need -= 1

        # 3s that must move left across 2s:
        # in the middle zone [c1, c1+c2), every 3 must cross later 2s.
        need = 0  # number of pending 3s needing to cross current boundary
        for i in range(c1 + c2 - 1, c1 - 1, -1):
            if a[i] == 3:
                need += 1
            if i < n - 1 and need > 0 and locked[i] == 1:
                ans += 1
            if a[i] == 2:
                need -= 1

        return ans

class Solution:
    def countPartitions(self, nums: List[int]) -> int:
        total = sum(nums)
        left_sum = 0
        count = 0

        for i in range(len(nums) - 1):
            left_sum += nums[i]
            right_sum = total - left_sum
            if (left_sum - right_sum) % 2 == 0:
                count += 1

        return count

from typing import List

class Solution:
    def countMentions(self, numberOfUsers: int, events: List[List[str]]) -> List[int]:
        mentions = [0] * numberOfUsers

        # Sort by timestamp, and process OFFLINE before MESSAGE at same timestamp
        events.sort(key=lambda e: (int(e[1]), 0 if e[0] == "OFFLINE" else 1))

        # online_until[i] < current_time means user is online
        # if current_time < online_until[i], user is offline
        online_again_time = [0] * numberOfUsers

        for typ, ts, data in events:
            t = int(ts)

            if typ == "OFFLINE":
                user = int(data)
                online_again_time[user] = t + 60
            else:
                if data == "ALL":
                    for i in range(numberOfUsers):
                        mentions[i] += 1
                elif data == "HERE":
                    for i in range(numberOfUsers):
                        if online_again_time[i] <= t:
                            mentions[i] += 1
                else:
                    for token in data.split():
                        user = int(token[2:])
                        mentions[user] += 1

        return mentions

class Solution:
    def maxFrequency(self, nums: List[int], k: int) -> int:
        base = nums.count(k)
        ans = base

        # Choose a value v != k and convert some occurrences of v to k
        # by adding x = k - v on one subarray.
        # Inside that subarray:
        # - each v becomes k  => +1 gain
        # - each k becomes something else => -1 loss
        # For fixed v, find maximum subarray sum on weights:
        #   +1 if nums[i] == v
        #   -1 if nums[i] == k
        #    0 otherwise
        for v in range(1, 51):
            if v == k:
                continue

            best = 0
            cur = 0
            for num in nums:
                if num == v:
                    cur += 1
                elif num == k:
                    cur -= 1

                if cur < 0:
                    cur = 0
                if cur > best:
                    best = cur

            ans = max(ans, base + best)

        return ans

class Solution:
    def findValidPair(self, s: str) -> str:
        freq = {}
        for ch in s:
            freq[ch] = freq.get(ch, 0) + 1

        for i in range(len(s) - 1):
            a, b = s[i], s[i + 1]
            if a != b and freq[a] == int(a) and freq[b] == int(b):
                return a + b

        return ""

class Solution:
    def minCostGoodCaption(self, caption: str) -> str:
        n = len(caption)
        if n < 3:
            return ""

        a = [ord(c) - 97 for c in caption]
        INF = 10**18

        # suffix cost: cost to convert caption[i:] into a good caption
        dp = [INF] * (n + 1)
        choice = [None] * (n + 1)
        dp[n] = 0

        # prefix sums of conversion costs to each target character
        pref = [[0] * (n + 1) for _ in range(26)]
        for ch in range(26):
            ps = pref[ch]
            for i in range(n):
                ps[i + 1] = ps[i] + abs(a[i] - ch)

        def seg_cost(l, r, ch):
            return pref[ch][r] - pref[ch][l]

        def better(c1, c2):
            # Return True if candidate c1 is better than c2
            # candidate format: (total_cost, char, length, next_pos)
            if c2 is None:
                return True
            if c1[0] != c2[0]:
                return c1[0] < c2[0]
            if c1[1] != c2[1]:
                return c1[1] < c2[1]
            # same leading char; shorter block exposes later chars earlier,
            # which makes lexicographic comparison correct
            if c1[2] != c2[2]:
                return c1[2] < c2[2]
            return False

        for i in range(n - 1, -1, -1):
            best = None
            max_len = n - i
            for ch in range(26):
                # block length exactly 3
                if i + 3 <= n and dp[i + 3] < INF:
                    cand = (seg_cost(i, i + 3, ch) + dp[i + 3], ch, 3, i + 3)
                    if better(cand, best):
                        best = cand

                # block length >= 4 only if it reaches the end
                # because any longer internal block can be split into 3 + rest
                if max_len >= 4:
                    cand = (seg_cost(i, n, ch), ch, n - i, n)
                    if better(cand, best):
                        best = cand

            if best is not None:
                dp[i] = best[0]
                choice[i] = best

        if dp[0] >= INF:
            return ""

        res = []
        i = 0
        while i < n:
            _, ch, length, ni = choice[i]
            res.append(chr(ch + 97) * length)
            i = ni
        return "".join(res)

class Solution:
    def maxDifference(self, s: str) -> int:
        freq = {}
        for ch in s:
            freq[ch] = freq.get(ch, 0) + 1

        max_odd = float("-inf")
        min_even = float("inf")

        for count in freq.values():
            if count % 2 == 1:
                max_odd = max(max_odd, count)
            else:
                min_even = min(min_even, count)

        return max_odd - min_even

from typing import List
from math import gcd

class Solution:
    def minimumIncrements(self, nums: List[int], target: List[int]) -> int:
        m = len(target)
        full = 1 << m

        def lcm(a: int, b: int) -> int:
            return a // gcd(a, b) * b

        # lcms[mask] = lcm of target elements in mask
        lcms = [1] * full
        for mask in range(1, full):
            v = 1
            for i in range(m):
                if mask >> i & 1:
                    v = lcm(v, target[i])
            lcms[mask] = v

        INF = 10**18
        dp = [INF] * full
        dp[0] = 0

        for x in nums:
            ndp = dp[:]
            for mask in range(1, full):
                need = lcms[mask]
                inc = (need - x % need) % need
                for prev in range(full):
                    if dp[prev] == INF:
                        continue
                    new_mask = prev | mask
                    if dp[prev] + inc < ndp[new_mask]:
                        ndp[new_mask] = dp[prev] + inc
            dp = ndp

        return dp[full - 1]

class Solution:
    def assignElements(self, groups: List[int], elements: List[int]) -> List[int]:
        max_val = max(groups)
        best = [-1] * (max_val + 1)

        # For each element value, keep the smallest index where it appears.
        for i, x in enumerate(elements):
            if x <= max_val and best[x] == -1:
                best[x] = i

        # ans[v] = smallest index j such that elements[j] divides v
        ans = [-1] * (max_val + 1)

        # Sieve-like propagation over multiples.
        for d in range(1, max_val + 1):
            if best[d] == -1:
                continue
            idx = best[d]
            for multiple in range(d, max_val + 1, d):
                if ans[multiple] == -1 or idx < ans[multiple]:
                    ans[multiple] = idx

        return [ans[g] for g in groups]

class Solution:
    def maxStudentsOnBench(self, students: List[List[int]]) -> int:
        bench_to_students = {}

        for student_id, bench_id in students:
            if bench_id not in bench_to_students:
                bench_to_students[bench_id] = set()
            bench_to_students[bench_id].add(student_id)

        max_count = 0
        for student_set in bench_to_students.values():
            max_count = max(max_count, len(student_set))

        return max_count

class Solution:
    def sumOfGoodNumbers(self, nums: List[int], k: int) -> int:
        total = 0
        n = len(nums)

        for i in range(n):
            good = True

            if i - k >= 0 and nums[i] <= nums[i - k]:
                good = False
            if i + k < n and nums[i] <= nums[i + k]:
                good = False

            if good:
                total += nums[i]

        return total

class Solution:
    def separateSquares(self, squares: List[List[int]]) -> float:
        total_area = 0.0
        low = float("inf")
        high = 0.0

        for _, y, l in squares:
            total_area += l * l
            low = min(low, y)
            high = max(high, y + l)

        target = total_area / 2.0

        def area_below(Y: float) -> float:
            area = 0.0
            for _, y, l in squares:
                if Y <= y:
                    continue
                elif Y >= y + l:
                    area += l * l
                else:
                    area += l * (Y - y)
            return area

        for _ in range(70):
            mid = (low + high) / 2.0
            if area_below(mid) >= target:
                high = mid
            else:
                low = mid

        return high

from typing import List

class Solution:
    def separateSquares(self, squares: List[List[int]]) -> float:
        # Sweep line on y.
        # For each vertical slab [y_i, y_{i+1}), maintain the union length on x
        # of all active square intervals. Then area contributed by the slab is:
        # union_x_length * (y_{i+1} - y_i)
        #
        # After building all slabs, find the minimum y where accumulated union area
        # reaches half of total union area.

        events = []
        ys = set()

        for x, y, l in squares:
            x1, x2 = x, x + l
            y1, y2 = y, y + l
            events.append((y1, 1, x1, x2))   # add interval
            events.append((y2, -1, x1, x2))  # remove interval
            ys.add(y1)
            ys.add(y2)

        ys = sorted(ys)
        if not ys:
            return 0.0

        # Coordinate compression for x endpoints
        xs = set()
        for _, _, x1, x2 in events:
            xs.add(x1)
            xs.add(x2)
        xs = sorted(xs)
        x_id = {x: i for i, x in enumerate(xs)}

        # Segment tree over elementary intervals [xs[i], xs[i+1])
        n = len(xs) - 1
        if n <= 0:
            return float(ys[0])

        count = [0] * (4 * n)
        covered = [0] * (4 * n)

        def push_up(idx: int, l: int, r: int) -> None:
            if count[idx] > 0:
                covered[idx] = xs[r + 1] - xs[l]
            elif l == r:
                covered[idx] = 0
            else:
                covered[idx] = covered[idx * 2] + covered[idx * 2 + 1]

        def update(idx: int, l: int, r: int, ql: int, qr: int, val: int) -> None:
            if ql <= l and r <= qr:
                count[idx] += val
                push_up(idx, l, r)
                return
            mid = (l + r) // 2
            if ql <= mid:
                update(idx * 2, l, mid, ql, qr, val)
            if qr > mid:
                update(idx * 2 + 1, mid + 1, r, ql, qr, val)
            push_up(idx, l, r)

        # Group events by y
        events.sort()
        m = len(events)
        i = 0
        slabs = []  # (y_start, y_end, union_x_length)
        cur_y = events[0][0]

        while i < m:
            y = events[i][0]

            # Area on [cur_y, y) uses current covered x-length
            if y > cur_y:
                slabs.append((cur_y, y, covered[1]))
                cur_y = y

            # Apply all events at this y
            while i < m and events[i][0] == y:
                _, typ, x1, x2 = events[i]
                l = x_id[x1]
                r = x_id[x2] - 1
                if l <= r:
                    update(1, 0, n - 1, l, r, typ)
                i += 1

        total_area = 0
        for y1, y2, width in slabs:
            total_area += width * (y2 - y1)

        half = total_area / 2

        acc = 0.0
        for y1, y2, width in slabs:
            slab_area = width * (y2 - y1)
            if acc + slab_area < half:
                acc += slab_area
                continue

            if width == 0:
                return float(y1)

            remaining = half - acc
            return float(y1 + remaining / width)

        # Degenerate fallback
        return float(ys[0])

class Solution:
    def shortestMatchingSubstring(self, s: str, p: str) -> int:
        parts = p.split('*')
        a, b, c = parts[0], parts[1], parts[2]
        n = len(s)

        def kmp_occurrences(text: str, pat: str):
            if pat == "":
                return list(range(len(text) + 1))
            m = len(pat)
            lps = [0] * m
            j = 0
            for i in range(1, m):
                while j > 0 and pat[i] != pat[j]:
                    j = lps[j - 1]
                if pat[i] == pat[j]:
                    j += 1
                    lps[i] = j

            res = []
            j = 0
            for i, ch in enumerate(text):
                while j > 0 and ch != pat[j]:
                    j = lps[j - 1]
                if ch == pat[j]:
                    j += 1
                    if j == m:
                        res.append(i - m + 1)
                        j = lps[j - 1]
            return res

        occ_a = kmp_occurrences(s, a)
        occ_b = kmp_occurrences(s, b)
        occ_c = kmp_occurrences(s, c)

        INF = 10**18

        def build_next_positions(occ, pat_len):
            nxt = [INF] * (n + 1)
            if pat_len == 0:
                for i in range(n + 1):
                    nxt[i] = i
                return nxt
            mark = [False] * (n + 1)
            for pos in occ:
                mark[pos] = True
            last = INF
            for i in range(n, -1, -1):
                if i <= n - pat_len and mark[i]:
                    last = i
                nxt[i] = last
            return nxt

        next_b = build_next_positions(occ_b, len(b))
        next_c = build_next_positions(occ_c, len(c))

        ans = INF

        starts = occ_a if len(a) > 0 else list(range(n + 1))

        for i in starts:
            if i + len(a) > n:
                continue
            j = next_b[i + len(a)]
            if j == INF or j + len(b) > n:
                continue
            k = next_c[j + len(b)]
            if k == INF or k + len(c) > n:
                continue
            ans = min(ans, k + len(c) - i)

        return -1 if ans == INF else ans

class Solution:
    def hasSpecialSubstring(self, s: str, k: int) -> bool:
        n = len(s)

        for i in range(n - k + 1):
            ch = s[i]

            # Check all characters in the substring are the same
            if s[i:i + k] != ch * k:
                continue

            # Check left boundary
            if i > 0 and s[i - 1] == ch:
                continue

            # Check right boundary
            if i + k < n and s[i + k] == ch:
                continue

            return True

        return False

class Solution:
    def maxSubstringLength(self, s: str, k: int) -> bool:
        if k == 0:
            return True

        n = len(s)
        first = [-1] * 26
        last = [-1] * 26

        for i, ch in enumerate(s):
            idx = ord(ch) - ord('a')
            if first[idx] == -1:
                first[idx] = i
            last[idx] = i

        intervals = []

        for c in range(26):
            if first[c] == -1:
                continue

            l = first[c]
            r = last[c]
            j = l
            valid = True

            while j <= r:
                idx = ord(s[j]) - ord('a')
                if first[idx] < l:
                    valid = False
                    break
                r = max(r, last[idx])
                j += 1

            if valid and not (l == 0 and r == n - 1):
                intervals.append((r, l))

        intervals.sort()
        count = 0
        end = -1

        for r, l in intervals:
            if l > end:
                count += 1
                end = r
                if count >= k:
                    return True

        return False

class Solution:
    def longestCommonPrefix(self, s: str, t: str) -> int:
        i = 0
        n, m = len(s), len(t)

        while i < n and i < m and s[i] == t[i]:
            i += 1

        # No mismatch within the comparable range
        if i == n or i == m:
            return i

        # Try removing s[i]
        j = i + 1
        k = i
        while j < n and k < m and s[j] == t[k]:
            j += 1
            k += 1

        return k

class Solution:
    def hasSameDigits(self, s: str) -> bool:
        digits = [int(c) for c in s]

        while len(digits) > 2:
            digits = [(digits[i] + digits[i + 1]) % 10 for i in range(len(digits) - 1)]

        return digits[0] == digits[1]

class Solution:
    def maxSum(self, grid: List[List[int]], limits: List[int], k: int) -> int:
        candidates = []

        for row, limit in zip(grid, limits):
            if limit == 0:
                continue
            row.sort(reverse=True)
            candidates.extend(row[:limit])

        candidates.sort(reverse=True)
        return sum(candidates[:k])

class Solution:
    def maxDistance(self, side: int, points: List[List[int]], k: int) -> int:
        n = len(points)

        def pos_on_perimeter(x: int, y: int) -> int:
            if y == 0:
                return x
            if x == side:
                return side + y
            if y == side:
                return 3 * side - x
            return 4 * side - y

        arr = []
        for x, y in points:
            arr.append((pos_on_perimeter(x, y), x, y))
        arr.sort()

        pos = [p for p, _, _ in arr]
        xs = [x for _, x, _ in arr]
        ys = [y for _, y, _ in arr]

        m = 4 * side

        ext_pos = pos + [p + m for p in pos]
        ext_xs = xs + xs
        ext_ys = ys + ys

        def manhattan(i: int, j: int) -> int:
            return abs(ext_xs[i] - ext_xs[j]) + abs(ext_ys[i] - ext_ys[j])

        def can(d: int) -> bool:
            nxt = [0] * (2 * n)
            r = 0
            for i in range(2 * n):
                if r < i + 1:
                    r = i + 1
                while r < 2 * n and manhattan(i, r) < d:
                    r += 1
                nxt[i] = r

            for s in range(n):
                limit = s + n
                chosen = 1
                cur = s
                first = s
                ok = True

                while chosen < k:
                    ni = nxt[cur]
                    if ni >= limit:
                        ok = False
                        break
                    cur = ni
                    chosen += 1

                if not ok:
                    continue

                if manhattan(cur, first) < d:
                    continue

                return True

            return False

        lo, hi = 0, 2 * side
        while lo < hi:
            mid = (lo + hi + 1) // 2
            if can(mid):
                lo = mid
            else:
                hi = mid - 1
        return lo

class Solution:
    def transformArray(self, nums: List[int]) -> List[int]:
        zeros = 0
        for num in nums:
            if num % 2 == 0:
                zeros += 1

        ones = len(nums) - zeros
        return [0] * zeros + [1] * ones

from functools import lru_cache
from typing import List

class Solution:
    def minCost(self, nums: List[int]) -> int:
        n = len(nums)

        @lru_cache(None)
        def dp(i: int, carry: int) -> int:
            # carry is the one remaining element from the previous step
            # next available elements are: carry, nums[i], nums[i+1]
            remaining = n - i

            # If no new elements remain, remove carry alone
            if remaining == 0:
                return carry

            # If only one new element remains, remove both together
            if remaining == 1:
                return max(carry, nums[i])

            a, b, c = carry, nums[i], nums[i + 1]

            # Choose any two among (a, b, c), pay max of removed two,
            # and the third becomes the carry for the next step.
            return min(
                max(a, b) + dp(i + 2, c),
                max(a, c) + dp(i + 2, b),
                max(b, c) + dp(i + 2, a),
            )

        if n <= 2:
            return max(nums)

        # Initial step uses the first three elements
        a, b, c = nums[0], nums[1], nums[2]
        return min(
            max(a, b) + dp(3, c),
            max(a, c) + dp(3, b),
            max(b, c) + dp(3, a),
        )

from typing import List
from math import factorial

class Solution:
    def permute(self, n: int, k: int) -> List[int]:
        LIMIT = 10**18

        def cap_mul(a: int, b: int) -> int:
            if a == 0 or b == 0:
                return 0
            if a > LIMIT // b:
                return LIMIT
            return a * b

        # capped factorials
        fact = [1] * (n + 1)
        for i in range(1, n + 1):
            fact[i] = min(LIMIT, fact[i - 1] * i)

        def count_ways(odd_cnt: int, even_cnt: int, next_parity: int) -> int:
            # next_parity: 1 for odd, 0 for even
            total = odd_cnt + even_cnt
            if total == 0:
                return 1

            if next_parity == 1:
                if odd_cnt != even_cnt and odd_cnt != even_cnt + 1:
                    return 0
                return cap_mul(fact[odd_cnt], fact[even_cnt])
            else:
                if even_cnt != odd_cnt and even_cnt != odd_cnt + 1:
                    return 0
                return cap_mul(fact[odd_cnt], fact[even_cnt])

        odds = [x for x in range(1, n + 1) if x % 2 == 1]
        evens = [x for x in range(1, n + 1) if x % 2 == 0]

        total_count = 0
        odd_cnt, even_cnt = len(odds), len(evens)

        if odd_cnt == even_cnt:
            total_count = min(LIMIT, 2 * cap_mul(fact[odd_cnt], fact[even_cnt]))
        elif odd_cnt == even_cnt + 1:
            total_count = cap_mul(fact[odd_cnt], fact[even_cnt])
        elif even_cnt == odd_cnt + 1:
            total_count = cap_mul(fact[odd_cnt], fact[even_cnt])
        else:
            total_count = 0

        if k > total_count:
            return []

        used = [False] * (n + 1)
        res = []
        rem_odd, rem_even = odd_cnt, even_cnt
        prev_parity = -1  # none

        for pos in range(n):
            for x in range(1, n + 1):
                if used[x]:
                    continue
                p = x % 2
                if prev_parity != -1 and p == prev_parity:
                    continue

                no = rem_odd - (1 if p == 1 else 0)
                ne = rem_even - (1 if p == 0 else 0)

                if no < 0 or ne < 0:
                    continue

                if no + ne == 0:
                    cnt = 1
                else:
                    cnt = count_ways(no, ne, 1 - p)

                if k > cnt:
                    k -= cnt
                else:
                    res.append(x)
                    used[x] = True
                    rem_odd, rem_even = no, ne
                    prev_parity = p
                    break

        return res

class Solution:
    def largestInteger(self, nums: List[int], k: int) -> int:
        from collections import defaultdict

        count = defaultdict(int)
        n = len(nums)

        for i in range(n - k + 1):
            seen = set(nums[i:i + k])
            for x in seen:
                count[x] += 1

        ans = -1
        for x, c in count.items():
            if c == 1:
                ans = max(ans, x)

        return ans

class Solution:
    def longestPalindromicSubsequence(self, s: str, k: int) -> int:
        n = len(s)

        def cost(a: str, b: str) -> int:
            d = abs(ord(a) - ord(b))
            return min(d, 26 - d)

        # dp(i, j, rem) = longest palindromic subsequence in s[i:j+1]
        # using at most rem operations
        from functools import lru_cache

        @lru_cache(None)
        def dp(i: int, j: int, rem: int) -> int:
            if i > j:
                return 0
            if i == j:
                return 1

            res = max(dp(i + 1, j, rem), dp(i, j - 1, rem))

            c = cost(s[i], s[j])
            if c <= rem:
                res = max(res, 2 + dp(i + 1, j - 1, rem - c))

            return res

        return dp(0, n - 1, k)

class Solution:
    def maxSum(self, nums: List[int], k: int, m: int) -> int:
        n = len(nums)

        prefix = [0] * (n + 1)
        for i in range(n):
            prefix[i + 1] = prefix[i] + nums[i]

        NEG = -10**18

        # dp[t][i]: maximum sum using exactly t non-overlapping subarrays
        # from first i elements (nums[0..i-1])
        dp = [[NEG] * (n + 1) for _ in range(k + 1)]
        for i in range(n + 1):
            dp[0][i] = 0

        for t in range(1, k + 1):
            best = NEG
            for i in range(1, n + 1):
                # Do not end a subarray at position i-1
                dp[t][i] = dp[t][i - 1]

                # Update best candidate for starting a subarray that ends at i-1
                if i >= m and dp[t - 1][i - m] != NEG:
                    best = max(best, dp[t - 1][i - m] - prefix[i - m])

                # End one subarray at i-1 with length at least m
                if best != NEG:
                    dp[t][i] = max(dp[t][i], prefix[i] + best)

        return dp[k][n]

class Solution:
    def generateString(self, str1: str, str2: str) -> str:
        n, m = len(str1), len(str2)
        L = n + m - 1
        word = ['?'] * L

        # Apply all forced equalities from 'T'
        for i, ch in enumerate(str1):
            if ch == 'T':
                for j in range(m):
                    pos = i + j
                    c = str2[j]
                    if word[pos] == '?':
                        word[pos] = c
                    elif word[pos] != c:
                        return ""

        # Build for each F-window the list of positions still flexible
        f_positions = []
        for i, ch in enumerate(str1):
            if ch == 'F':
                fixed_equal = True
                positions = []
                for j in range(m):
                    pos = i + j
                    if word[pos] == '?':
                        positions.append(pos)
                        fixed_equal = False
                    elif word[pos] != str2[j]:
                        fixed_equal = False
                if fixed_equal:
                    return ""
                f_positions.append(positions)

        # Greedily fill remaining '?' with smallest letters while preserving feasibility
        def valid_if_set(pos, c):
            # Check only F-windows containing pos
            left = max(0, pos - m + 1)
            right = min(n - 1, pos)
            for i in range(left, right + 1):
                if str1[i] != 'F':
                    continue
                has_mismatch = False
                has_unknown = False
                for j in range(m):
                    p = i + j
                    cur = c if p == pos else word[p]
                    if cur == '?':
                        has_unknown = True
                    elif cur != str2[j]:
                        has_mismatch = True
                        break
                # If after assigning pos=c, this F-window becomes fully equal, invalid
                if not has_mismatch and not has_unknown:
                    return False
            return True

        for pos in range(L):
            if word[pos] == '?':
                for c in "abcdefghijklmnopqrstuvwxyz":
                    if valid_if_set(pos, c):
                        word[pos] = c
                        break
                else:
                    return ""

        res = "".join(word)

        # Final verification
        for i, ch in enumerate(str1):
            sub = res[i:i + m]
            if ch == 'T':
                if sub != str2:
                    return ""
            else:
                if sub == str2:
                    return ""
        return res

class Solution:
    def maxProfit(self, workers: List[int], tasks: List[List[int]]) -> int:
        from collections import Counter, defaultdict
        import heapq

        worker_count = Counter(workers)
        grouped = defaultdict(list)

        for skill, profit in tasks:
            grouped[skill].append(profit)

        total = 0
        best_unassigned = 0
        heap = []

        for skill, profits in grouped.items():
            profits.sort(reverse=True)
            cnt = worker_count.get(skill, 0)

            take = min(cnt, len(profits))
            if take:
                total += sum(profits[:take])

            for p in profits[take:]:
                if p > best_unassigned:
                    best_unassigned = p

        return total + best_unassigned

class Solution:
    def numOfUnplacedFruits(self, fruits: List[int], baskets: List[int]) -> int:
        n = len(baskets)
        used = [False] * n
        unplaced = 0

        for fruit in fruits:
            placed = False
            for i in range(n):
                if not used[i] and baskets[i] >= fruit:
                    used[i] = True
                    placed = True
                    break
            if not placed:
                unplaced += 1

        return unplaced

from typing import List

class Solution:
    def numOfUnplacedFruits(self, fruits: List[int], baskets: List[int]) -> int:
        n = len(baskets)

        size = 1
        while size < n:
            size <<= 1

        seg = [0] * (2 * size)

        for i in range(n):
            seg[size + i] = baskets[i]
        for i in range(size - 1, 0, -1):
            seg[i] = max(seg[i << 1], seg[i << 1 | 1])

        def update(idx: int, val: int) -> None:
            pos = size + idx
            seg[pos] = val
            pos >>= 1
            while pos:
                seg[pos] = max(seg[pos << 1], seg[pos << 1 | 1])
                pos >>= 1

        def find_leftmost(x: int) -> int:
            if seg[1] < x:
                return -1
            pos = 1
            while pos < size:
                if seg[pos << 1] >= x:
                    pos <<= 1
                else:
                    pos = pos << 1 | 1
            return pos - size

        unplaced = 0

        for fruit in fruits:
            idx = find_leftmost(fruit)
            if idx == -1:
                unplaced += 1
            else:
                update(idx, 0)

        return unplaced

class Solution:
    def applySubstitutions(self, replacements: List[List[str]], text: str) -> str:
        mp = {k: v for k, v in replacements}
        memo = {}

        def resolve(key: str) -> str:
            if key in memo:
                return memo[key]

            s = mp[key]
            res = []
            i = 0

            while i < len(s):
                if s[i] == '%':
                    j = s.find('%', i + 1)
                    sub_key = s[i + 1:j]
                    res.append(resolve(sub_key))
                    i = j + 1
                else:
                    res.append(s[i])
                    i += 1

            memo[key] = "".join(res)
            return memo[key]

        res = []
        i = 0

        while i < len(text):
            if text[i] == '%':
                j = text.find('%', i + 1)
                key = text[i + 1:j]
                res.append(resolve(key))
                i = j + 1
            else:
                res.append(text[i])
                i += 1

        return "".join(res)

class Solution:
    def totalNumbers(self, digits: List[int]) -> int:
        nums = set()
        n = len(digits)

        for i in range(n):
            if digits[i] == 0:
                continue
            for j in range(n):
                if j == i:
                    continue
                for k in range(n):
                    if k == i or k == j:
                        continue
                    if digits[k] % 2 == 0:
                        num = digits[i] * 100 + digits[j] * 10 + digits[k]
                        nums.add(num)

        return len(nums)

