from collections import defaultdict

class Solution:
    def longestCommonPrefix(self, words: List[str], k: int) -> List[int]:
        n = len(words)
        if n - 1 < k:
            return [0] * n

        # Count how many words share each prefix.
        prefix_count = defaultdict(int)
        max_len = 0
        for w in words:
            max_len = max(max_len, len(w))
            p = []
            for ch in w:
                p.append(ch)
                prefix_count[''.join(p)] += 1

        # For each length, count how many prefixes appear in at least k words.
        valid_at_len = [0] * (max_len + 1)
        for p, cnt in prefix_count.items():
            if cnt >= k:
                valid_at_len[len(p)] += 1

        # Best length globally with at least one prefix appearing >= k times.
        global_best = 0
        for l in range(1, max_len + 1):
            if valid_at_len[l] > 0:
                global_best = l

        # Fragile lengths: exactly one valid prefix at this length, and that prefix count == k.
        fragile = [None] * (max_len + 1)
        if global_best > 0:
            by_len = defaultdict(list)
            for p, cnt in prefix_count.items():
                if cnt >= k:
                    by_len[len(p)].append((p, cnt))
            for l, arr in by_len.items():
                if len(arr) == 1 and arr[0][1] == k:
                    fragile[l] = arr[0][0]

        # Precompute fallback best length if some fragile lengths disappear.
        # For each length l, after removing the only valid prefix at l (if fragile),
        # the best remaining answer is the largest t such that:
        # - t != l and valid_at_len[t] > 0, or
        # - t == l and valid_at_len[t] > 1
        fallback = [0] * (max_len + 1)
        best1 = best2 = 0
        for l in range(1, max_len + 1):
            if valid_at_len[l] > 0:
                if l > best1:
                    best2 = best1
                    best1 = l
                elif l > best2:
                    best2 = l

        for l in range(max_len + 1):
            if l == best1 and valid_at_len[l] == 1:
                fallback[l] = best2
            else:
                fallback[l] = best1

        ans = [0] * n

        for i, w in enumerate(words):
            # Check which fragile lengths are broken by removing this word.
            broken_best = global_best
            p = []
            for ch in w:
                p.append(ch)
                s = ''.join(p)
                l = len(s)
                if fragile[l] == s:
                    if broken_best == l:
                        broken_best = fallback[l]

            ans[i] = broken_best

        return ans

class Solution:
    def maxSum(self, nums: List[int]) -> int:
        positives = set()
        best = max(nums)

        for x in nums:
            if x > 0:
                positives.add(x)

        if positives:
            return sum(positives)
        return best

class Solution:
    def minZeroArray(self, nums: List[int], queries: List[List[int]]) -> int:
        n = len(nums)
        m = len(queries)

        def can_make_zero(k: int) -> bool:
            # For each index, collect values of usable queries covering it.
            # Since n <= 10 and k <= 1000, subset-sum DP per index is feasible.
            cover_vals = [[] for _ in range(n)]
            for i in range(k):
                l, r, val = queries[i]
                for idx in range(l, r + 1):
                    cover_vals[idx].append(val)

            for idx in range(n):
                target = nums[idx]
                if target == 0:
                    continue

                dp = [False] * (target + 1)
                dp[0] = True

                for v in cover_vals[idx]:
                    for s in range(target, v - 1, -1):
                        if dp[s - v]:
                            dp[s] = True

                if not dp[target]:
                    return False

            return True

        if all(x == 0 for x in nums):
            return 0

        if not can_make_zero(m):
            return -1

        lo, hi = 1, m
        ans = m
        while lo <= hi:
            mid = (lo + hi) // 2
            if can_make_zero(mid):
                ans = mid
                hi = mid - 1
            else:
                lo = mid + 1

        return ans

class Solution:
    def beautifulNumbers(self, l: int, r: int) -> int:
        from functools import lru_cache

        def count_beautiful(n: int) -> int:
            if n <= 0:
                return 0

            digits = list(map(int, str(n)))
            m = len(digits)

            @lru_cache(None)
            def dp(pos: int, tight: bool, started: bool, s: int, p: int) -> int:
                if pos == m:
                    if not started:
                        return 0
                    return 1 if p % s == 0 else 0

                limit = digits[pos] if tight else 9
                ans = 0

                for d in range(limit + 1):
                    ntight = tight and (d == limit)
                    if not started and d == 0:
                        ans += dp(pos + 1, ntight, False, 0, 1)
                    else:
                        if not started:
                            ans += dp(pos + 1, ntight, True, d, d)
                        else:
                            ans += dp(pos + 1, ntight, True, s + d, p * d)
                return ans

            return dp(0, True, False, 0, 1)

        return count_beautiful(r) - count_beautiful(l - 1)

class Solution:
    def phonePrefix(self, numbers: List[str]) -> bool:
        numbers.sort()

        for i in range(len(numbers) - 1):
            if numbers[i + 1].startswith(numbers[i]):
                return False

        return True

class Solution:
    def maxContainers(self, n: int, w: int, maxWeight: int) -> int:
        return min(n * n, maxWeight // w)

class Solution:
    def numberOfComponents(self, properties: List[List[int]], k: int) -> int:
        n = len(properties)
        sets = [set(arr) for arr in properties]

        parent = list(range(n))

        def find(x):
            while parent[x] != x:
                parent[x] = parent[parent[x]]
                x = parent[x]
            return x

        def union(a, b):
            ra, rb = find(a), find(b)
            if ra != rb:
                parent[rb] = ra

        for i in range(n):
            for j in range(i + 1, n):
                if len(sets[i] & sets[j]) >= k:
                    union(i, j)

        return sum(1 for i in range(n) if find(i) == i)

