class Solution:
    def longestPalindrome(self, s: str, t: str) -> int:
        def longest_pal_substring(x: str) -> int:
            n = len(x)
            best = 1

            for center in range(n):
                l = r = center
                while l >= 0 and r < n and x[l] == x[r]:
                    best = max(best, r - l + 1)
                    l -= 1
                    r += 1

                l, r = center, center + 1
                while l >= 0 and r < n and x[l] == x[r]:
                    best = max(best, r - l + 1)
                    l -= 1
                    r += 1

            return best

        n, m = len(s), len(t)

        # dp[i][j] = longest common prefix length of s[i:] and reversed(t)[j:]
        rt = t[::-1]
        dp = [[0] * (m + 1) for _ in range(n + 1)]
        ans = max(longest_pal_substring(s), longest_pal_substring(t))

        for i in range(n - 1, -1, -1):
            for j in range(m - 1, -1, -1):
                if s[i] == rt[j]:
                    dp[i][j] = dp[i + 1][j + 1] + 1

        # Build palindrome using non-empty substrings from both s and t.
        # If k matched pairs are used across the boundary:
        # - even length: 2*k
        # - odd length : 2*k + 1, possible if we can extend on one side
        for i in range(n):
            for j in range(m):
                k = dp[i][m - 1 - j]  # matches s[i:] with t[:j+1] reversed
                if k > 0:
                    ans = max(ans, 2 * k)
                    if i + k < n or j - k >= 0:
                        ans = max(ans, 2 * k + 1)

        return ans

