def encode(message):
    vowels = "aeiouAEIOU"
    shifted = {
        'a': 'c', 'e': 'g', 'i': 'k', 'o': 'q', 'u': 'w',
        'A': 'C', 'E': 'G', 'I': 'K', 'O': 'Q', 'U': 'W'
    }

    result = []
    for ch in message:
        if ch in vowels:
            ch = shifted[ch]
        result.append(ch.swapcase())
    return ''.join(result)

