def get_odd_collatz(n):
    odds = set()

    while True:
        if n % 2 == 1:
            odds.add(n)
        if n == 1:
            break
        if n % 2 == 0:
            n //= 2
        else:
            n = 3 * n + 1

    return sorted(odds)

def valid_date(date):
    if not date or not isinstance(date, str):
        return False

    parts = date.split('-')
    if len(parts) != 3:
        return False

    month_str, day_str, year_str = parts

    if len(month_str) != 2 or len(day_str) != 2 or len(year_str) != 4:
        return False

    if not (month_str.isdigit() and day_str.isdigit() and year_str.isdigit()):
        return False

    month = int(month_str)
    day = int(day_str)

    if month < 1 or month > 12:
        return False

    if month in (1, 3, 5, 7, 8, 10, 12):
        return 1 <= day <= 31
    elif month in (4, 6, 9, 11):
        return 1 <= day <= 30
    else:  # month == 2
        return 1 <= day <= 29

def split_words(txt):
