    for i in range(len(lst)):
        if i > 0 and lst[i] < lst[i - 1]:
            return False

        counts[lst[i]] = counts.get(lst[i], 0) + 1
        if counts[lst[i]] > 2:
            return False

    return True

def intersection(interval1, interval2):
    a1, b1 = interval1
    a2, b2 = interval2

    left = max(a1, a2)
    right = min(b1, b2)

    if left > right:
        return "NO"

    length = right - left

    if length < 2:
        return "NO"

    for i in range(2, int(length ** 0.5) + 1):
        if length % i == 0:
            return "NO"

    return "YES"

def prod_signs(arr):
    if not arr:
        return None
    sign_product = 1
    magnitude_sum = 0
    for x in arr:
        magnitude_sum += abs(x)
        if x == 0:
            sign_product = 0
        elif x < 0:
            sign_product *= -1
    return magnitude_sum * sign_product

def minPath(grid, k):
    n = len(grid)

    # Map each value to its position
    pos = [None] * (n * n + 1)
    for i in range(n):
        for j in range(n):
            pos[grid[i][j]] = (i, j)

    # Precompute neighbors for each value
    neighbors = [[] for _ in range(n * n + 1)]
    for val in range(1, n * n + 1):
        i, j = pos[val]
        for di, dj in ((1, 0), (-1, 0), (0, 1), (0, -1)):
            ni, nj = i + di, j + dj
            if 0 <= ni < n and 0 <= nj < n:
                neighbors[val].append(grid[ni][nj])

    # dp_prev[v] tells whether there exists a path of current remaining length
    # starting from value v and staying within the currently valid set
    valid = [True] * (n * n + 1)

    # Build answer greedily, filtering possible starting values each step
    current = list(range(1, n * n + 1))
    answer = []

    for step in range(k):
        best = min(current)
        answer.append(best)

        if step == k - 1:
            break

        # Next possible positions are neighbors of all positions with value == best
        next_current = []
        seen = set()
        for v in current:
            if v == best:
                for nb in neighbors[v]:
                    if nb not in seen:
                        seen.add(nb)
                        next_current.append(nb)
        current = next_current

    return answer

def tri(n):
    res = [1]
    if n == 0:
        return res

    vals = {1: 3}
    for i in range(1, n + 1):
        if i == 1:
            res.append(3)
        elif i % 2 == 0:
            vals[i] = 1 + i // 2
            res.append(vals[i])
        else:
            vals[i] = vals[i - 1] + vals[i - 2] + (1 + (i + 1) // 2)
            res.append(vals[i])
    return res

def digits(n):
    product = 1
    found_odd = False

    for ch in str(n):
        d = int(ch)
        if d % 2 == 1:
            product *= d
            found_odd = True

    return product if found_odd else 0

def is_nested(string):
    depth = 0
    max_depth = 0

    for ch in string:
        if ch == '[':
            depth += 1
            if depth > max_depth:
                max_depth = depth
        else:  # ch == ']'
            if depth > 0:
                depth -= 1

    return max_depth >= 2

import math

def sum_squares(lst):
    return sum(math.ceil(x) ** 2 for x in lst)

def check_if_last_char_is_a_letter(txt):
    if not txt:
        return False
    if not txt[-1].isalpha():
        return False
    return len(txt) == 1 or txt[-2] == " "

def can_arrange(arr):
    for i in range(len(arr) - 1, 0, -1):
        if arr[i] <= arr[i - 1]:
            return i
    return -1

def largest_smallest_integers(lst):
    negatives = [x for x in lst if x < 0]
    positives = [x for x in lst if x > 0]

    a = max(negatives) if negatives else None
    b = min(positives) if positives else None

    return (a, b)

def compare_one(a, b):
    def to_float(x):
        if isinstance(x, str):
            x = x.replace(",", ".")
        return float(x)

    a_val = to_float(a)
    b_val = to_float(b)

    if a_val > b_val:
        return a
    if b_val > a_val:
        return b
    return None

def fix_spaces(text):
    result = []
    i = 0

    while i < len(text):
        if text[i] == ' ':
            j = i
            while j < len(text) and text[j] == ' ':
                j += 1

            count = j - i
            if count > 2:
                result.append('-')
            else:
                result.append('_' * count)

            i = j
        else:
            result.append(text[i])
            i += 1

    return ''.join(result)

def file_name_check(file_name):
    if file_name.count('.') != 1:
        return 'No'

    name, ext = file_name.split('.')

    if not name:
        return 'No'

    if not name[0].isalpha():
        return 'No'

    if ext not in ['txt', 'exe', 'dll']:
        return 'No'

    digit_count = sum(ch.isdigit() for ch in file_name)
    if digit_count > 3:
        return 'No'

    return 'Yes'

def sum_squares(lst):
    total = 0
    for i, x in enumerate(lst):
        if i % 3 == 0:
            total += x ** 2
        elif i % 4 == 0:
            total += x ** 3
        else:
            total += x
    return total

def words_in_sentence(sentence):
    def is_prime(n):
        if n < 2:
            return False
        for i in range(2, int(n ** 0.5) + 1):
            if n % i == 0:
                return False
        return True

    words = sentence.split()
    return " ".join(word for word in words if is_prime(len(word)))

def specialFilter(nums):
    count = 0
    odd_digits = {'1', '3', '5', '7', '9'}

    for num in nums:
        if num > 10:
            s = str(num)
            if s[0] in odd_digits and s[-1] in odd_digits:
                count += 1

    return count

def bf(planet1, planet2):
    planets = (
        "Mercury", "Venus", "Earth", "Mars",
        "Jupiter", "Saturn", "Uranus", "Neptune"
    )

    if planet1 not in planets or planet2 not in planets:
        return ()

    i1 = planets.index(planet1)
    i2 = planets.index(planet2)

    start, end = sorted((i1, i2))
    return planets[start + 1:end]

def x_or_y(n, x, y):
    if n < 2:
        return y
    for i in range(2, int(n ** 0.5) + 1):
        if n % i == 0:
            return y
    return x

def Strongest_Extension(class_name, extensions):
    def strength(ext):
        upper = sum(1 for c in ext if c.isupper())
        lower = sum(1 for c in ext if c.islower())
        return upper - lower

    strongest = extensions[0]
    max_strength = strength(strongest)

    for ext in extensions[1:]:
        s = strength(ext)
        if s > max_strength:
            max_strength = s
            strongest = ext

    return f"{class_name}.{strongest}"

def cycpattern_check(a, b):
    if len(b) == 0:
        return True
    for i in range(len(b)):
        rotated = b[i:] + b[:i]
        if rotated in a:
            return True
    return False

def even_odd_count(num):
    even = 0
    odd = 0

    for digit in str(abs(num)):
        if int(digit) % 2 == 0:
            even += 1
        else:
            odd += 1

    return (even, odd)

def right_angle_triangle(a, b, c):
    sides = sorted([a, b, c])
    return sides[0] > 0 and sides[0] + sides[1] > sides[2] and sides[0]**2 + sides[1]**2 == sides[2]**2

def eat(number, need, remaining):
    eaten_now = min(need, remaining)
    return [number + eaten_now, remaining - eaten_now]

def do_algebra(operator, operand):
    expression = str(operand[0])
    for op, num in zip(operator, operand[1:]):
        expression += op + str(num)
    return eval(expression)

def solve(s):
    if any(ch.isalpha() for ch in s):
        return ''.join(ch.swapcase() if ch.isalpha() else ch for ch in s)
    return s[::-1]

def string_to_md5(text):
    if text == "":
        return None

    import hashlib
    return hashlib.md5(text.encode()).hexdigest()

def generate_integers(a, b):
    start, end = sorted((a, b))
    return [x for x in range(start, end + 1) if x % 2 == 0 and x < 10]
